const book: BibleBook = {
  id: 'proverbs',
  name: 'Provérbios',
  englishName: 'Proverbs',
  testament: 'old',
  chapters: {
    1: [
      { v: 1, en: 'The proverbs of Solomon, the son of David, king of Israel:', pt: 'Provérbios de Salomão, filho de Davi, rei de Israel:' },
      { v: 2, en: 'to know wisdom and instruction; to discern the words of understanding;', pt: 'Para se conhecer a sabedoria e a instrução; para se entenderem as palavras de inteligência;' },
      { v: 3, en: 'to receive instruction in wise dealing, in righteousness, justice, and equity;', pt: 'para se instruir em sábio procedimento, em retidão, justiça e eqüidade;' },
      { v: 4, en: 'to give prudence to the simple, knowledge and discretion to the young man:', pt: 'para se dar aos simples prudência, e aos jovens conhecimento e bom siso.' },
      { v: 5, en: 'that the wise man may hear, and increase in learning; that the man of understanding may attain to sound counsel:', pt: 'Ouça também, o sábio e cresça em ciência, e o entendido adquira habilidade,' },
      { v: 6, en: 'to understand a proverb, and parables, the words and riddles of the wise.', pt: 'para entender provérbios e parábolas, as palavras dos sábios, e seus enigmas.' },
      { v: 7, en: 'The fear of Yahweh is the beginning of knowledge; but the foolish despise wisdom and instruction.', pt: 'O temor do Senhor é o princípio do conhecimento; mas os insensatos desprezam a sabedoria e a instrução.' },
      { v: 8, en: 'My son, listen to your father’s instruction, and don’t forsake your mother’s teaching:', pt: 'Filho meu, ouve a instrução de teu pai, e não deixes o ensino de tua mãe.' },
      { v: 9, en: 'for they will be a garland to grace your head, and chains around your neck.', pt: 'Porque eles serão uma grinalda de graça para a tua cabeça, e colares para o teu pescoço.' },
      { v: 10, en: 'My son, if sinners entice you, don’t consent.', pt: 'Filho meu, se os pecadores te quiserem seduzir, não consintas.' },
      { v: 11, en: 'If they say, “Come with us. Let’s lay in wait for blood. Let’s lurk secretly for the innocent without cause.', pt: 'Se disserem: Vem conosco; embosquemo-nos para derramar sangue; espreitemos sem razão o inocente;' },
      { v: 12, en: 'Let’s swallow them up alive like Sheol, and whole, like those who go down into the pit.', pt: 'traguemo-los vivos, como o Seol, e inteiros como os que descem à cova;' },
      { v: 13, en: 'We’ll find all valuable wealth. We’ll fill our houses with plunder.', pt: 'acharemos toda sorte de bens preciosos; encheremos as nossas casas de despojos;' },
      { v: 14, en: 'You shall cast your lot among us. We’ll all have one purse.”', pt: 'lançarás a tua sorte entre nós; teremos todos uma só bolsa;' },
      { v: 15, en: 'My son, don’t walk on the path with them. Keep your foot from their path,', pt: 'filho meu, não andes no caminho com eles; guarda da sua vereda o teu pé,' },
      { v: 16, en: 'for their feet run to evil. They hurry to shed blood.', pt: 'porque os seus pés correm para o mal, e eles se apressam a derramar sangue.' },
      { v: 17, en: 'For in vain is the net spread in the sight of any bird:', pt: 'Pois debalde se estende a rede à vista de qualquer ave.' },
      { v: 18, en: 'but these lay wait for their own blood. They lurk secretly for their own lives.', pt: 'Mas estes se põem em emboscadas contra o seu próprio sangue, e as suas próprias vidas espreitam.' },
      { v: 19, en: 'So are the ways of everyone who is greedy for gain. It takes away the life of its owners.', pt: 'Tais são as veredas de todo aquele que se entrega à cobiça; ela tira a vida dos que a possuem.' },
      { v: 20, en: 'Wisdom calls aloud in the street. She utters her voice in the public squares.', pt: 'A suprema sabedoria altissonantemente clama nas ruas; nas praças levanta a sua voz.' },
      { v: 21, en: 'She calls at the head of noisy places. At the entrance of the city gates, she utters her words:', pt: 'Do alto dos muros clama; às entradas das portas e na cidade profere as suas palavras:' },
      { v: 22, en: '“How long, you simple ones, will you love simplicity? How long will mockers delight themselves in mockery, and fools hate knowledge?', pt: 'Até quando, ó estúpidos, amareis a estupidez? e até quando se deleitarão no escárnio os escarnecedores, e odiarão os insensatos o conhecimento?' },
      { v: 23, en: 'Turn at my reproof. Behold, I will pour out my spirit on you. I will make known my words to you.', pt: 'Convertei-vos pela minha repreensão; eis que derramarei sobre vós o meu; espírito e vos farei saber as minhas palavras.' },
      { v: 24, en: 'Because I have called, and you have refused; I have stretched out my hand, and no one has paid attention;', pt: 'Mas, porque clamei, e vós recusastes; porque estendi a minha mão, e nao houve quem desse atenção;' },
      { v: 25, en: 'but you have ignored all my counsel, and wanted none of my reproof;', pt: 'antes desprezastes todo o meu conselho, e não fizestes caso da minha repreensão;' },
      { v: 26, en: 'I also will laugh at your disaster. I will mock when calamity overtakes you;', pt: 'também eu me rirei no dia da vossa calamidade; zombarei, quando sobrevier o vosso terror,' },
      { v: 27, en: 'when calamity overtakes you like a storm, when your disaster comes on like a whirlwind; when distress and anguish come on you.', pt: 'quando o terror vos sobrevier como tempestade, e a vossa calamidade passar como redemoinho, e quando vos sobrevierem aperto e angústia.' },
      { v: 28, en: 'Then will they call on me, but I will not answer. They will seek me diligently, but they will not find me;', pt: 'Então a mim clamarão, mas eu não responderei; diligentemente me buscarão, mas não me acharão.' },
      { v: 29, en: 'because they hated knowledge, and didn’t choose the fear of Yahweh.', pt: 'Porquanto aborreceram o conhecimento, e não preferiram o temor do Senhor;' },
      { v: 30, en: 'They wanted none of my counsel. They despised all my reproof.', pt: 'não quiseram o meu conselho e desprezaram toda a minha repreensão;' },
      { v: 31, en: 'Therefore they will eat of the fruit of their own way, and be filled with their own schemes.', pt: 'portanto comerão do fruto do seu caminho e se fartarão dos seus próprios conselhos.' },
      { v: 32, en: 'For the backsliding of the simple will kill them. The careless ease of fools will destroy them.', pt: 'Porque o desvio dos néscios os matará, e a prosperidade dos loucos os destruirá.' },
      { v: 33, en: 'But whoever listens to me will dwell securely, and will be at ease, without fear of harm.”', pt: 'Mas o que me der ouvidos habitará em segurança, e estará tranqüilo, sem receio do mal.' },
    ],
    2: [
      { v: 1, en: 'My son, if you will receive my words, and store up my commandments within you;', pt: 'Filho meu, se aceitares as minhas palavras, e entesourares contigo os meus mandamentos,' },
      { v: 2, en: 'So as to turn your ear to wisdom, and apply your heart to understanding;', pt: 'para fazeres atento à sabedoria o teu ouvido, e para inclinares o teu coração ao entendimento;' },
      { v: 3, en: 'Yes, if you call out for discernment, and lift up your voice for understanding;', pt: 'sim, se clamares por discernimento, e por entendimento alçares a tua voz;' },
      { v: 4, en: 'If you seek her as silver, and search for her as for hidden treasures:', pt: 'se o buscares como a prata e o procurares como a tesouros escondidos;' },
      { v: 5, en: 'then you will understand the fear of Yahweh, and find the knowledge of God.', pt: 'então entenderás o temor do Senhor, e acharás o conhecimento de Deus.' },
      { v: 6, en: 'For Yahweh gives wisdom. Out of his mouth comes knowledge and understanding.', pt: 'Porque o Senhor dá a sabedoria; da sua boca procedem o conhecimento e o entendimento;' },
      { v: 7, en: 'He lays up sound wisdom for the upright. He is a shield to those who walk in integrity;', pt: 'ele reserva a verdadeira sabedoria para os retos; e escudo para os que caminham em integridade,' },
      { v: 8, en: 'that he may guard the paths of justice, and preserve the way of his saints.', pt: 'guardando-lhes as veredas da justiça, e preservando o caminho dos seus santos.' },
      { v: 9, en: 'Then you will understand righteousness and justice, equity and every good path.', pt: 'Então entenderás a retidão, a justiça, a eqüidade, e todas as boas veredas.' },
      { v: 10, en: 'For wisdom will enter into your heart. Knowledge will be pleasant to your soul.', pt: 'Pois a sabedoria entrará no teu coração, e o conhecimento será aprazível à tua alma;' },
      { v: 11, en: 'Discretion will watch over you. Understanding will keep you,', pt: 'o bom siso te protegerá, e o discernimento e guardará;' },
      { v: 12, en: 'to deliver you from the way of evil, from the men who speak perverse things;', pt: 'para te livrar do mau caminho, e do homem que diz coisas perversas;' },
      { v: 13, en: 'who forsake the paths of uprightness, to walk in the ways of darkness;', pt: 'dos que deixam as veredas da retidão, para andarem pelos caminhos das trevas;' },
      { v: 14, en: 'who rejoice to do evil, and delight in the perverseness of evil;', pt: 'que se alegram de fazer o mal, e se deleitam nas perversidades dos maus;' },
      { v: 15, en: 'who are crooked in their ways, and wayward in their paths:', pt: 'dos que são tortuosos nas suas veredas; e iníquos nas suas carreiras;' },
      { v: 16, en: 'To deliver you from the strange woman, even from the foreigner who flatters with her words;', pt: 'e para te livrar da mulher estranha, da estrangeira que lisonjeia com suas palavras;' },
      { v: 17, en: 'who forsakes the friend of her youth, and forgets the covenant of her God:', pt: 'a qual abandona o companheiro da sua mocidade e se esquece do concerto do seu Deus;' },
      { v: 18, en: 'for her house leads down to death, her paths to the departed spirits.', pt: 'pois a sua casa se inclina para a morte, e as suas veredas para as sombras.' },
      { v: 19, en: 'None who go to her return again, neither do they attain to the paths of life:', pt: 'Nenhum dos que se dirigirem a ela, tornara a sair, nem retomará as veredas da vida.' },
      { v: 20, en: 'that you may walk in the way of good men, and keep the paths of the righteous.', pt: 'Assim andarás pelo caminho dos bons, e guardarás as veredas dos justos.' },
      { v: 21, en: 'For the upright will dwell in the land. The perfect will remain in it.', pt: 'Porque os retos habitarão a terra, e os íntegros permanecerão nela.' },
      { v: 22, en: 'But the wicked will be cut off from the land. The treacherous will be rooted out of it.', pt: 'Mas os ímpios serão exterminados da terra, e dela os aleivosos serão desarraigados.' },
    ],
    3: [
      { v: 1, en: 'My son, don’t forget my teaching; but let your heart keep my commandments:', pt: 'Filho meu, não te esqueças da minha instrução, e o teu coração guarde os meus mandamentos;' },
      { v: 2, en: 'for length of days, and years of life, and peace, will they add to you.', pt: 'porque eles te darão longura de dias, e anos de vida e paz.' },
      { v: 3, en: 'Don’t let kindness and truth forsake you. Bind them around your neck. Write them on the tablet of your heart.', pt: 'Não se afastem de ti a benignidade e a fidelidade; ata-as ao teu pescoço, escreve-as na tábua do teu coração;' },
      { v: 4, en: 'So you will find favor, and good understanding in the sight of God and man.', pt: 'assim acharás favor e bom entendimento à vista de Deus e dos homens.' },
      { v: 5, en: 'Trust in Yahweh with all your heart, and don’t lean on your own understanding.', pt: 'Confia no Senhor de todo o teu coração, e não te estribes no teu próprio entendimento.' },
      { v: 6, en: 'In all your ways acknowledge him, and he will make your paths straight.', pt: 'Reconhece-o em todos os teus caminhos, e ele endireitará as tuas veredas.' },
      { v: 7, en: 'Don’t be wise in your own eyes. Fear Yahweh, and depart from evil.', pt: 'Não sejas sábio a teus próprios olhos; teme ao Senhor e aparta-te do mal.' },
      { v: 8, en: 'It will be health to your body, and nourishment to your bones.', pt: 'Isso será saúde para a tua carne; e refrigério para os teus ossos.' },
      { v: 9, en: 'Honor Yahweh with your substance, with the first fruits of all your increase:', pt: 'Honra ao Senhor com os teus bens, e com as primícias de toda a tua renda;' },
      { v: 10, en: 'so your barns will be filled with plenty, and your vats will overflow with new wine.', pt: 'assim se encherão de fartura os teus celeiros, e trasbordarão de mosto os teus lagares.' },
      { v: 11, en: 'My son, don’t despise Yahweh’s discipline, neither be weary of his reproof:', pt: 'Filho meu, não rejeites a disciplina do Senhor, nem te enojes da sua repreensão;' },
      { v: 12, en: 'for whom Yahweh loves, he reproves; even as a father reproves the son in whom he delights.', pt: 'porque o Senhor repreende aquele a quem ama, assim como o pai ao filho a quem quer bem.' },
      { v: 13, en: 'Happy is the man who finds wisdom, the man who gets understanding.', pt: 'Feliz é o homem que acha sabedoria, e o homem que adquire entendimento;' },
      { v: 14, en: 'For her good profit is better than getting silver, and her return is better than fine gold.', pt: 'pois melhor é o lucro que ela dá do que o lucro da prata, e a sua renda do que o ouro.' },
      { v: 15, en: 'She is more precious than rubies. None of the things you can desire are to be compared to her.', pt: 'Mais preciosa é do que as jóias, e nada do que possas desejar é comparável a ela.' },
      { v: 16, en: 'Length of days is in her right hand. In her left hand are riches and honor.', pt: 'Longura de dias há na sua mão direita; na sua esquerda riquezas e honra.' },
      { v: 17, en: 'Her ways are ways of pleasantness. All her paths are peace.', pt: 'Os seus caminhos são caminhos de delícias, e todas as suas veredas são paz.' },
      { v: 18, en: 'She is a tree of life to those who lay hold of her. Happy is everyone who retains her.', pt: 'É árvore da vida para os que dela lançam mão, e bem-aventurado é todo aquele que a retém.' },
      { v: 19, en: 'By wisdom Yahweh founded the earth. By understanding, he established the heavens.', pt: 'O Senhor pela sabedoria fundou a terra; pelo entendimento estabeleceu o céu.' },
      { v: 20, en: 'By his knowledge, the depths were broken up, and the skies drop down the dew.', pt: 'Pelo seu conhecimento se fendem os abismos, e as nuvens destilam o orvalho.' },
      { v: 21, en: 'My son, let them not depart from your eyes. Keep sound wisdom and discretion:', pt: 'Filho meu, não se apartem estas coisas dos teus olhos: guarda a verdadeira sabedoria e o bom siso;' },
      { v: 22, en: 'so they will be life to your soul, and grace for your neck.', pt: 'assim serão elas vida para a tua alma, e adorno para o teu pescoço.' },
      { v: 23, en: 'Then you shall walk in your way securely. Your foot won’t stumble.', pt: 'Então andarás seguro pelo teu caminho, e não tropeçará o teu pé.' },
      { v: 24, en: 'When you lie down, you will not be afraid. Yes, you will lie down, and your sleep will be sweet.', pt: 'Quando te deitares, não temerás; sim, tu te deitarás e o teu sono será suave.' },
      { v: 25, en: 'Don’t be afraid of sudden fear, neither of the desolation of the wicked, when it comes:', pt: 'Não temas o pavor repentino, nem a assolação dos ímpios quando vier.' },
      { v: 26, en: 'for Yahweh will be your confidence, and will keep your foot from being taken.', pt: 'Porque o Senhor será a tua confiança, e guardará os teus pés de serem presos.' },
      { v: 27, en: 'Don’t withhold good from those to whom it is due, when it is in the power of your hand to do it.', pt: 'Não negues o bem a quem de direito, estando no teu poder fazê-lo.' },
      { v: 28, en: 'Don’t say to your neighbor, “Go, and come again; tomorrow I will give it to you,” when you have it by you.', pt: 'Não digas ao teu próximo: Vai, e volta, amanhã to darei; tendo-o tu contigo.' },
      { v: 29, en: 'Don’t devise evil against your neighbor, since he dwells securely by you.', pt: 'Não maquines o mal contra o teu próximo, que habita contigo confiadamente.' },
      { v: 30, en: 'Don’t strive with a man without cause, if he has done you no harm.', pt: 'Não contendas com um homem, sem motivo, não te havendo ele feito o mal.' },
      { v: 31, en: 'Don’t envy the man of violence. Choose none of his ways.', pt: 'Não tenhas inveja do homem violento, nem escolhas nenhum de seus caminhos.' },
      { v: 32, en: 'For the perverse is an abomination to Yahweh, but his friendship is with the upright.', pt: 'Porque o perverso é abominação para o Senhor, mas com os retos está o seu segredo.' },
      { v: 33, en: 'Yahweh’s curse is in the house of the wicked, but he blesses the habitation of the righteous.', pt: 'A maldição do Senhor habita na casa do ímpio, mas ele abençoa a habitação dos justos.' },
      { v: 34, en: 'Surely he mocks the mockers, but he gives grace to the humble.', pt: 'Ele escarnece dos escarnecedores, mas dá graça aos humildes.' },
      { v: 35, en: 'The wise will inherit glory, but shame will be the promotion of fools.', pt: 'Os sábios herdarão honra, mas a exaltação dos loucos se converte em ignomínia.' },
    ],
    4: [
      { v: 1, en: 'Listen, sons, to a father’s instruction. Pay attention and know understanding;', pt: 'Ouvi, filhos, a instrução do pai, e estai atentos para conhecerdes o entendimento.' },
      { v: 2, en: 'for I give you sound learning. Don’t forsake my law.', pt: 'Pois eu vos dou boa doutrina; não abandoneis o meu ensino.' },
      { v: 3, en: 'For I was a son to my father, tender and an only child in the sight of my mother.', pt: 'Quando eu era filho aos pés de meu, pai, tenro e único em estima diante de minha mãe,' },
      { v: 4, en: 'He taught me, and said to me: “Let your heart retain my words. Keep my commandments, and live.', pt: 'ele me ensinava, e me dizia: Retenha o teu coração as minhas palavras; guarda os meus mandamentos, e vive.' },
      { v: 5, en: 'Get wisdom. Get understanding. Don’t forget, and don’t deviate from the words of my mouth.', pt: 'Adquire a sabedoria, adquire o entendimento; não te esqueças nem te desvies das palavras da minha boca.' },
      { v: 6, en: 'Don’t forsake her, and she will preserve you. Love her, and she will keep you.', pt: 'Não a abandones, e ela te guardará; ama-a, e ela te preservará.' },
      { v: 7, en: 'Wisdom is supreme. Get wisdom. Yes, though it costs all your possessions, get understanding.', pt: 'A sabedoria é a coisa principal; adquire, pois, a sabedoria; sim, com tudo o que possuis adquire o entendimento.' },
      { v: 8, en: 'Esteem her, and she will exalt you. She will bring you to honor, when you embrace her.', pt: 'Estima-a, e ela te exaltará; se a abraçares, ela te honrará.' },
      { v: 9, en: 'She will give to your head a garland of grace. She will deliver a crown of splendor to you.”', pt: 'Ela dará à tua cabeça uma grinalda de graça; e uma coroa de glória te entregará.' },
      { v: 10, en: 'Listen, my son, and receive my sayings. The years of your life will be many.', pt: 'Ouve, filho meu, e aceita as minhas palavras, para que se multipliquem os anos da tua vida.' },
      { v: 11, en: 'I have taught you in the way of wisdom. I have led you in straight paths.', pt: 'Eu te ensinei o caminho da sabedoria; guiei-te pelas veredas da retidão.' },
      { v: 12, en: 'When you go, your steps will not be hampered. When you run, you will not stumble.', pt: 'Quando andares, não se embaraçarão os teus passos; e se correres, não tropeçarás.' },
      { v: 13, en: 'Take firm hold of instruction. Don’t let her go. Keep her, for she is your life.', pt: 'Apega-te à instrução e não a largues; guarda-a, porque ela é a tua vida.' },
      { v: 14, en: 'Don’t enter into the path of the wicked. Don’t walk in the way of evil men.', pt: 'Não entres na vereda dos ímpios, nem andes pelo caminho dos maus.' },
      { v: 15, en: 'Avoid it, and don’t pass by it. Turn from it, and pass on.', pt: 'Evita-o, não passes por ele; desvia-te dele e passa de largo.' },
      { v: 16, en: 'For they don’t sleep, unless they do evil. Their sleep is taken away, unless they make someone fall.', pt: 'Pois não dormem, se não fizerem o mal, e foge deles o sono se não fizerem tropeçar alguém.' },
      { v: 17, en: 'For they eat the bread of wickedness, and drink the wine of violence.', pt: 'Porque comem o pão da impiedade, e bebem o vinho da violência.' },
      { v: 18, en: 'But the path of the righteous is like the dawning light, that shines more and more until the perfect day.', pt: 'Mas a vereda dos justos é como a luz da aurora que vai brilhando mais e mais até ser dia perfeito.' },
      { v: 19, en: 'The way of the wicked is like darkness. They don’t know what they stumble over.', pt: 'O caminho dos ímpios é como a escuridão: não sabem eles em que tropeçam.' },
      { v: 20, en: 'My son, attend to my words. Turn your ear to my sayings.', pt: 'Filho meu, atenta para as minhas palavras; inclina o teu ouvido às minhas instroções.' },
      { v: 21, en: 'Let them not depart from your eyes. Keep them in the center of your heart.', pt: 'Não se apartem elas de diante dos teus olhos; guarda-as dentro do teu coração.' },
      { v: 22, en: 'For they are life to those who find them, and health to their whole body.', pt: 'Porque são vida para os que as encontram, e saúde para todo o seu corpo.' },
      { v: 23, en: 'Keep your heart with all diligence, for out of it is the wellspring of life.', pt: 'Guarda com toda a diligência o teu coração, porque dele procedem as fontes da vida.' },
      { v: 24, en: 'Put away from yourself a perverse mouth. Put corrupt lips far from you.', pt: 'Desvia de ti a malignidade da boca, e alonga de ti a perversidade dos lábios.' },
      { v: 25, en: 'Let your eyes look straight ahead. Fix your gaze directly before you.', pt: 'Dirijam-se os teus olhos para a frente, e olhem as tuas pálpebras diretamente diante de ti.' },
      { v: 26, en: 'Make the path of your feet level. Let all of your ways be established.', pt: 'Pondera a vereda de teus pés, e serão seguros todos os teus caminhos.' },
      { v: 27, en: 'Don’t turn to the right hand nor to the left. Remove your foot from evil.', pt: 'Não declines nem para a direita nem para a esquerda; retira o teu pé do mal.' },
    ],
    5: [
      { v: 1, en: 'My son, pay attention to my wisdom. Turn your ear to my understanding:', pt: 'Filho meu, atende à minha sabedoria; inclinão teu ouvido à minha prudência;' },
      { v: 2, en: 'that you may maintain discretion, that your lips may preserve knowledge.', pt: 'para que observes a discrição, e os teus lábios guardem o conhecimento.' },
      { v: 3, en: 'For the lips of an adulteress drip honey. Her mouth is smoother than oil,', pt: 'Porque os lábios da mulher licenciosa destilam mel, e a sua boca e mais macia do que o azeite;' },
      { v: 4, en: 'but in the end she is as bitter as wormwood, and as sharp as a two-edged sword.', pt: 'mas o seu fim é amargoso como o absinto, agudo como a espada de dois gumes.' },
      { v: 5, en: 'Her feet go down to death. Her steps lead straight to Sheol.', pt: 'Os seus pés descem à morte; os seus passos seguem no caminho do Seol.' },
      { v: 6, en: 'She gives no thought to the way of life. Her ways are crooked, and she doesn’t know it.', pt: 'Ela não pondera a vereda da vida; incertos são os seus caminhos, e ela o ignora.' },
      { v: 7, en: 'Now therefore, my sons, listen to me. Don’t depart from the words of my mouth.', pt: 'Agora, pois, filhos, dai-me ouvidos, e não vos desvieis das palavras da minha boca.' },
      { v: 8, en: 'Remove your way far from her. Don’t come near the door of her house,', pt: 'Afasta para longe dela o teu caminho, e não te aproximes da porta da sua casa;' },
      { v: 9, en: 'lest you give your honor to others, and your years to the cruel one;', pt: 'para que não dês a outros a tua honra, nem os teus anos a cruéis;' },
      { v: 10, en: 'lest strangers feast on your wealth, and your labors enrich another man’s house.', pt: 'para que não se fartem os estranhos dos teus bens, e não entrem os teus trabalhos na casa do estrangeiro,' },
      { v: 11, en: 'You will groan at your latter end, when your flesh and your body are consumed,', pt: 'e gemas no teu fim, quando se consumirem a tua carne e o teu corpo,' },
      { v: 12, en: 'and say, “How I have hated instruction, and my heart despised reproof;', pt: 'e digas: Como detestei a disciplina! e desprezou o meu coração a repreensão!' },
      { v: 13, en: 'neither have I obeyed the voice of my teachers, nor turned my ear to those who instructed me!', pt: 'e não escutei a voz dos que me ensinavam, nem aos que me instruíam inclinei o meu ouvido!' },
      { v: 14, en: 'I have come to the brink of utter ruin, among the gathered assembly.”', pt: 'Quase cheguei à ruína completa, no meio da congregação e da assembléia.' },
      { v: 15, en: 'Drink water out of your own cistern, running water out of your own well.', pt: 'Bebe a água da tua própria cisterna, e das correntes do teu poço.' },
      { v: 16, en: 'Should your springs overflow in the streets, streams of water in the public squares?', pt: 'Derramar-se-iam as tuas fontes para fora, e pelas ruas os ribeiros de águas?' },
      { v: 17, en: 'Let them be for yourself alone, not for strangers with you.', pt: 'Sejam para ti só, e não para os estranhos juntamente contigo.' },
      { v: 18, en: 'Let your spring be blessed. Rejoice in the wife of your youth.', pt: 'Seja bendito o teu manancial; e regozija-te na mulher da tua mocidade.' },
      { v: 19, en: 'A loving doe and a graceful deer— let her breasts satisfy you at all times. Be captivated always with her love.', pt: 'Como corça amorosa, e graciosa cabra montesa saciem-te os seus seios em todo o tempo; e pelo seu amor sê encantado perpetuamente.' },
      { v: 20, en: 'For why should you, my son, be captivated with an adulteress? Why embrace the bosom of another?', pt: 'E por que, filho meu, andarias atraído pela mulher licenciosa, e abraÇarias o seio da adúltera?' },
      { v: 21, en: 'For the ways of man are before Yahweh’s eyes. He examines all his paths.', pt: 'Porque os caminhos do homem estão diante dos olhos do Senhor, o qual observa todas as suas veredas.' },
      { v: 22, en: 'The evil deeds of the wicked ensnare him. The cords of his sin hold him firmly.', pt: 'Quanto ao ímpio, as suas próprias iniqüidades o prenderão, e pelas cordas do seu pecado será detido.' },
      { v: 23, en: 'He will die for lack of instruction. In the greatness of his folly, he will go astray.', pt: 'Ele morre pela falta de disciplina; e pelo excesso da sua loucura anda errado.' },
    ],
    6: [
      { v: 1, en: 'My son, if you have become collateral for your neighbor, if you have struck your hands in pledge for a stranger;', pt: 'Filho meu, se ficaste por fiador do teu próximo, se te empenhaste por um estranho,' },
      { v: 2, en: 'You are trapped by the words of your mouth. You are ensnared with the words of your mouth.', pt: 'estás enredado pelos teus lábios; estás preso pelas palavras da tua boca.' },
      { v: 3, en: 'Do this now, my son, and deliver yourself, since you have come into the hand of your neighbor. Go, humble yourself. Press your plea with your neighbor.', pt: 'Faze pois isto agora, filho meu, e livra-te, pois já caíste nas mãos do teu próximo; vai, humilha-te, e importuna o teu próximo;' },
      { v: 4, en: 'Give no sleep to your eyes, nor slumber to your eyelids.', pt: 'não dês sono aos teus olhos, nem adormecimento às tuas pálpebras;' },
      { v: 5, en: 'Free yourself, like a gazelle from the hand of the hunter, like a bird from the snare of the fowler.', pt: 'livra-te como a gazela da mão do caçador, e como a ave da mão do passarinheiro.' },
      { v: 6, en: 'Go to the ant, you sluggard. Consider her ways, and be wise;', pt: 'Vai ter com a formiga, ó preguiçoso, considera os seus caminhos, e sê sábio;' },
      { v: 7, en: 'which having no chief, overseer, or ruler,', pt: 'a qual, não tendo chefe, nem superintendente, nem governador,' },
      { v: 8, en: 'provides her bread in the summer, and gathers her food in the harvest.', pt: 'no verão faz a provisão do seu mantimento, e ajunta o seu alimento no tempo da ceifa.' },
      { v: 9, en: 'How long will you sleep, sluggard? When will you arise out of your sleep?', pt: 'o preguiçoso, até quando ficarás deitador? quando te levantarás do teu sono?' },
      { v: 10, en: 'A little sleep, a little slumber, a little folding of the hands to sleep:', pt: 'um pouco para dormir, um pouco para toscanejar, um pouco para cruzar as mãos em repouso;' },
      { v: 11, en: 'so your poverty will come as a robber, and your scarcity as an armed man.', pt: 'assim te sobrevirá a tua pobreza como um ladrão, e a tua necessidade como um homem armado.' },
      { v: 12, en: 'A worthless person, a man of iniquity, is he who walks with a perverse mouth;', pt: 'O homem vil, o homem iníquo, anda com a perversidade na boca,' },
      { v: 13, en: 'who winks with his eyes, who signals with his feet, who motions with his fingers;', pt: 'pisca os olhos, faz sinais com os pés, e acena com os dedos;' },
      { v: 14, en: 'in whose heart is perverseness, who devises evil continually, who always sows discord.', pt: 'perversidade há no seu coração; todo o tempo maquina o mal; anda semeando contendas.' },
      { v: 15, en: 'Therefore his calamity will come suddenly. He will be broken suddenly, and that without remedy.', pt: 'Pelo que a sua destruição virá repentinamente; subitamente será quebrantado, sem que haja cura.' },
      { v: 16, en: 'There are six things which Yahweh hates; yes, seven which are an abomination to him:', pt: 'Há seis coisas que o Senhor detesta; sim, há sete que ele abomina:' },
      { v: 17, en: 'haughty eyes, a lying tongue, hands that shed innocent blood;', pt: 'olhos altivos, língua mentirosa, e mãos que derramam sangue inocente;' },
      { v: 18, en: 'a heart that devises wicked schemes, feet that are swift in running to mischief,', pt: 'coração que maquina projetos iníquos, pés que se apressam a correr para o mal;' },
      { v: 19, en: 'a false witness who utters lies, and he who sows discord among brothers.', pt: 'testemunha falsa que profere mentiras, e o que semeia contendas entre irmãos.' },
      { v: 20, en: 'My son, keep your father’s commandment, and don’t forsake your mother’s teaching.', pt: 'Filho meu, guarda o mandamento de, teu pai, e não abandones a instrução de tua mãe;' },
      { v: 21, en: 'Bind them continually on your heart. Tie them around your neck.', pt: 'ata-os perpetuamente ao teu coração, e pendura-os ao teu pescoço.' },
      { v: 22, en: 'When you walk, it will lead you. When you sleep, it will watch over you. When you awake, it will talk with you.', pt: 'Quando caminhares, isso te guiará; quando te deitares, te guardará; quando acordares, falará contigo.' },
      { v: 23, en: 'For the commandment is a lamp, and the law is light. Reproofs of instruction are the way of life,', pt: 'Porque o mandamento é uma lâmpada, e a instrução uma luz; e as repreensões da disciplina são o caminho da vida,' },
      { v: 24, en: 'to keep you from the immoral woman, from the flattery of the wayward wife’s tongue.', pt: 'para te guardarem da mulher má, e das lisonjas da língua da adúltera.' },
      { v: 25, en: 'Don’t lust after her beauty in your heart, neither let her captivate you with her eyelids.', pt: 'Não cobices no teu coração a sua formosura, nem te deixes prender pelos seus olhares.' },
      { v: 26, en: 'For a prostitute reduces you to a piece of bread. The adulteress hunts for your precious life.', pt: 'Porque o preço da prostituta é apenas um bocado de pão, mas a adúltera anda à caça da própria vida do homem.' },
      { v: 27, en: 'Can a man scoop fire into his lap, and his clothes not be burned?', pt: 'Pode alguém tomar fogo no seu seio, sem que os seus vestidos se queimem?' },
      { v: 28, en: 'Or can one walk on hot coals, and his feet not be scorched?', pt: 'Ou andará sobre as brasas sem que se queimem os seus pés?' },
      { v: 29, en: 'So is he who goes in to his neighbor’s wife. Whoever touches her will not be unpunished.', pt: 'Assim será o que entrar à mulher do seu proximo; não ficará inocente quem a tocar.' },
      { v: 30, en: 'Men don’t despise a thief, if he steals to satisfy himself when he is hungry:', pt: 'Não é desprezado o ladrão, mesmo quando furta para saciar a fome?' },
      { v: 31, en: 'but if he is found, he shall restore seven times. He shall give all the wealth of his house.', pt: 'E, se for apanhado, pagará sete vezes tanto, dando até todos os bens de sua casa.' },
      { v: 32, en: 'He who commits adultery with a woman is void of understanding. He who does it destroys his own soul.', pt: 'O que adultera com uma mulher é falto de entendimento; destrói-se a si mesmo, quem assim procede.' },
      { v: 33, en: 'He will get wounds and dishonor. His reproach will not be wiped away.', pt: 'Receberá feridas e ignomínia, e o seu opróbrio nunca se apagará;' },
      { v: 34, en: 'For jealousy arouses the fury of the husband. He won’t spare in the day of vengeance.', pt: 'porque o ciúme enfurece ao marido, que de maneira nenhuma poupará no dia da vingança.' },
      { v: 35, en: 'He won’t regard any ransom, neither will he rest content, though you give many gifts.', pt: 'Não aceitará resgate algum, nem se aplacará, ainda que multipliques os presentes.' },
    ],
    7: [
      { v: 1, en: 'My son, keep my words. Lay up my commandments within you.', pt: 'Filho meu, guarda as minhas palavras, e entesoura contigo os meus mandamentos.' },
      { v: 2, en: 'Keep my commandments and live! Guard my teaching as the apple of your eye.', pt: 'Observa os meus mandamentos e vive; guarda a minha lei, como a menina dos teus olhos.' },
      { v: 3, en: 'Bind them on your fingers. Write them on the tablet of your heart.', pt: 'Ata-os aos teus dedos, escreve-os na tábua do teu coração.' },
      { v: 4, en: 'Tell wisdom, “You are my sister.” Call understanding your relative,', pt: 'Dize à sabedoria: Tu és minha irmã; e chama ao entendimento teu amigo íntimo,' },
      { v: 5, en: 'that they may keep you from the strange woman, from the foreigner who flatters with her words.', pt: 'para te guardarem da mulher alheia, da adúltera, que lisonjeia com as suas palavras.' },
      { v: 6, en: 'For at the window of my house, I looked out through my lattice.', pt: 'Porque da janela da minha casa, por minhas grades olhando eu,' },
      { v: 7, en: 'I saw among the simple ones. I discerned among the youths a young man void of understanding,', pt: 'vi entre os simples, divisei entre os jovens, um mancebo falto de juízo,' },
      { v: 8, en: 'passing through the street near her corner, he went the way to her house,', pt: 'que passava pela rua junto à esquina da mulher adúltera e que seguia o caminho da sua casa,' },
      { v: 9, en: 'in the twilight, in the evening of the day, in the middle of the night and in the darkness.', pt: 'no crepúsculo, à tarde do dia, à noite fechada e na escuridão;' },
      { v: 10, en: 'Behold, there a woman met him with the attire of a prostitute, and with crafty intent.', pt: 'e eis que uma mulher lhe saiu ao encontro, ornada à moda das prostitutas, e astuta de coração.' },
      { v: 11, en: 'She is loud and defiant. Her feet don’t stay in her house.', pt: 'Ela é turbulenta e obstinada; não param em casa os seus pés;' },
      { v: 12, en: 'Now she is in the streets, now in the squares, and lurking at every corner.', pt: 'ora está ela pelas ruas, ora pelas praças, espreitando por todos os cantos.' },
      { v: 13, en: 'So she caught him, and kissed him. With an impudent face she said to him:', pt: 'Pegou dele, pois, e o beijou; e com semblante impudico lhe disse:' },
      { v: 14, en: '“Sacrifices of peace offerings are with me. Today I have paid my vows.', pt: 'Sacrifícios pacíficos tenho comigo; hoje paguei os meus votos.' },
      { v: 15, en: 'Therefore I came out to meet you, to diligently seek your face, and I have found you.', pt: 'Por isso saí ao teu encontro a buscar-te diligentemente, e te achei.' },
      { v: 16, en: 'I have spread my couch with carpets of tapestry, with striped cloths of the yarn of Egypt.', pt: 'Já cobri a minha cama de cobertas, de colchas de linho do Egito.' },
      { v: 17, en: 'I have perfumed my bed with myrrh, aloes, and cinnamon.', pt: 'Já perfumei o meu leito com mirra, aloés e cinamomo.' },
      { v: 18, en: 'Come, let’s take our fill of loving until the morning. Let’s solace ourselves with loving.', pt: 'Vem, saciemo-nos de amores até pela manhã; alegremo-nos com amores.' },
      { v: 19, en: 'For my husband isn’t at home. He has gone on a long journey.', pt: 'Porque meu marido não está em casa; foi fazer uma jornada ao longe;' },
      { v: 20, en: 'He has taken a bag of money with him. He will come home at the full moon.”', pt: 'um saquitel de dinheiro levou na mão; só lá para o dia da lua cheia voltará para casa.' },
      { v: 21, en: 'With persuasive words, she led him astray. With the flattering of her lips, she seduced him.', pt: 'Ela o faz ceder com a multidão das suas palavras sedutoras, com as lisonjas dos seus lábios o arrasta.' },
      { v: 22, en: 'He followed her immediately, as an ox goes to the slaughter, as a fool stepping into a noose.', pt: 'Ele a segue logo, como boi que vai ao matadouro, e como o louco ao castigo das prisões;' },
      { v: 23, en: 'Until an arrow strikes through his liver, as a bird hurries to the snare, and doesn’t know that it will cost his life.', pt: 'até que uma flecha lhe atravesse o fígado, como a ave que se apressa para o laço, sem saber que está armado contra a sua vida.' },
      { v: 24, en: 'Now therefore, sons, listen to me. Pay attention to the words of my mouth.', pt: 'Agora, pois, filhos, ouvi-me, e estai atentos às palavras da minha boca.' },
      { v: 25, en: 'Don’t let your heart turn to her ways. Don’t go astray in her paths,', pt: 'Não se desvie para os seus caminhos o teu coração, e não andes perdido nas suas veredas.' },
      { v: 26, en: 'for she has thrown down many wounded. Yes, all her slain are a mighty army.', pt: 'Porque ela a muitos tem feito cair feridos; e são muitíssimos os que por ela foram mortos.' },
      { v: 27, en: 'Her house is the way to Sheol, going down to the rooms of death.', pt: 'Caminho de Seol é a sua casa, o qual desce às câmaras da morte.' },
    ],
    8: [
      { v: 1, en: 'Doesn’t wisdom cry out? Doesn’t understanding raise her voice?', pt: 'Não clama porventura a sabedoria, e não faz o entendimento soar a sua voz?' },
      { v: 2, en: 'On the top of high places by the way, where the paths meet, she stands.', pt: 'No cume das alturas, junto ao caminho, nas encruzilhadas das veredas ela se coloca.' },
      { v: 3, en: 'Beside the gates, at the entry of the city, at the entry doors, she cries aloud:', pt: 'Junto às portas, à entrada da cidade, e à entrada das portas está clamando:' },
      { v: 4, en: '“To you men, I call! I send my voice to the sons of mankind.', pt: 'A vós, ó homens, clamo; e a minha voz se dirige aos filhos dos homens.' },
      { v: 5, en: 'You simple, understand prudence. You fools, be of an understanding heart.', pt: 'Aprendei, ó simples, a prudência; entendei, ó loucos, a sabedoria.' },
      { v: 6, en: 'Hear, for I will speak excellent things. The opening of my lips is for right things.', pt: 'Ouvi vós, porque profiro coisas excelentes; os meus lábios se abrem para a eqüidade.' },
      { v: 7, en: 'For my mouth speaks truth. Wickedness is an abomination to my lips.', pt: 'Porque a minha boca profere a verdade, os meus lábios abominam a impiedade.' },
      { v: 8, en: 'All the words of my mouth are in righteousness. There is nothing crooked or perverse in them.', pt: 'Justas são todas as palavras da minha boca; não há nelas nenhuma coisa tortuosa nem perversa.' },
      { v: 9, en: 'They are all plain to him who understands, right to those who find knowledge.', pt: 'Todas elas são retas para o que bem as entende, e justas para os que acham o conhecimento.' },
      { v: 10, en: 'Receive my instruction rather than silver; knowledge rather than choice gold.', pt: 'Aceitai antes a minha correção, e não a prata; e o conhecimento, antes do que o ouro escolhido.' },
      { v: 11, en: 'For wisdom is better than rubies. All the things that may be desired can’t be compared to it.', pt: 'Porque melhor é a sabedoria do que as jóias; e de tudo o que se deseja nada se pode comparar com ela.' },
      { v: 12, en: '“I, wisdom, have made prudence my dwelling. Find out knowledge and discretion.', pt: 'Eu, a sabedoria, habito com a prudência, e possuo o conhecimento e a discrição.' },
      { v: 13, en: 'The fear of Yahweh is to hate evil. I hate pride, arrogance, the evil way, and the perverse mouth.', pt: 'O temor do Senhor é odiar o mal; a soberba, e a arrogância, e o mau caminho, e a boca perversa, eu os odeio.' },
      { v: 14, en: 'Counsel and sound knowledge are mine. I have understanding and power.', pt: 'Meu é o conselho, e a verdadeira sabedoria; eu sou o entendimento; minha é a fortaleza.' },
      { v: 15, en: 'By me kings reign, and princes decree justice.', pt: 'Por mim reinam os reis, e os príncipes decretam o que justo.' },
      { v: 16, en: 'By me princes rule; nobles, and all the righteous rulers of the earth.', pt: 'Por mim governam os príncipes e os nobres, sim, todos os juízes da terra.' },
      { v: 17, en: 'I love those who love me. Those who seek me diligently will find me.', pt: 'Eu amo aos que me amam, e os que diligentemente me buscam me acharão.' },
      { v: 18, en: 'With me are riches, honor, enduring wealth, and prosperity.', pt: 'Riquezas e honra estão comigo; sim, riquezas duráveis e justiça.' },
      { v: 19, en: 'My fruit is better than gold, yes, than fine gold; my yield than choice silver.', pt: 'Melhor é o meu fruto do que o ouro, sim, do que o ouro refinado; e a minha renda melhor do que a prata escolhida.' },
      { v: 20, en: 'I walk in the way of righteousness, in the middle of the paths of justice;', pt: 'Ando pelo caminho da retidão, no meio das veredas da justiça,' },
      { v: 21, en: 'that I may give wealth to those who love me. I fill their treasuries.', pt: 'dotando de bens permanentes os que me amam, e enchendo os seus tesouros.' },
      { v: 22, en: '“Yahweh possessed me in the beginning of his work, before his deeds of old.', pt: 'O Senhor me criou como a primeira das suas obras, o princípio dos seus feitos mais antigos.' },
      { v: 23, en: 'I was set up from everlasting, from the beginning, before the earth existed.', pt: 'Desde a eternidade fui constituída, desde o princípio, antes de existir a terra.' },
      { v: 24, en: 'When there were no depths, I was born, when there were no springs abounding with water.', pt: 'Antes de haver abismos, fui gerada, e antes ainda de haver fontes cheias d\'água.' },
      { v: 25, en: 'Before the mountains were settled in place, before the hills, I was born;', pt: 'Antes que os montes fossem firmados, antes dos outeiros eu nasci,' },
      { v: 26, en: 'while as yet he had not made the earth, nor the fields, nor the beginning of the dust of the world.', pt: 'quando ele ainda não tinha feito a terra com seus campos, nem sequer o princípio do pó do mundo.' },
      { v: 27, en: 'When he established the heavens, I was there; when he set a circle on the surface of the deep,', pt: 'Quando ele preparava os céus, aí estava eu; quando traçava um círculo sobre a face do abismo,' },
      { v: 28, en: 'when he established the clouds above, when the springs of the deep became strong,', pt: 'quando estabelecia o firmamento em cima, quando se firmavam as fontes do abismo,' },
      { v: 29, en: 'when he gave to the sea its boundary, that the waters should not violate his commandment, when he marked out the foundations of the earth;', pt: 'quando ele fixava ao mar o seu termo, para que as águas não traspassassem o seu mando, quando traçava os fundamentos da terra,' },
      { v: 30, en: 'then I was the craftsman by his side. I was a delight day by day, always rejoicing before him,', pt: 'então eu estava ao seu lado como arquiteto; e era cada dia as suas delícias, alegrando-me perante ele em todo o tempo;' },
      { v: 31, en: 'rejoicing in his whole world. My delight was with the sons of men.', pt: 'folgando no seu mundo habitável, e achando as minhas delícias com os filhos dos homens.' },
      { v: 32, en: '“Now therefore, my sons, listen to me, for blessed are those who keep my ways.', pt: 'Agora, pois, filhos, ouvi-me; porque felizes são os que guardam os meus caminhos.' },
      { v: 33, en: 'Hear instruction, and be wise. Don’t refuse it.', pt: 'Ouvi a correção, e sede sábios; e não a rejeiteis.' },
      { v: 34, en: 'Blessed is the man who hears me, watching daily at my gates, waiting at my door posts.', pt: 'Feliz é o homem que me dá ouvidos, velando cada dia às minhas entradas, esperando junto às ombreiras da minha porta.' },
      { v: 35, en: 'For whoever finds me, finds life, and will obtain favor from Yahweh.', pt: 'Porque o que me achar achará a vida, e alcançará o favor do Senhor.' },
      { v: 36, en: 'But he who sins against me wrongs his own soul. All those who hate me love death.”', pt: 'Mas o que pecar contra mim fará mal à sua própria alma; todos os que me odeiam amam a morte.' },
    ],
    9: [
      { v: 1, en: 'Wisdom has built her house. She has carved out her seven pillars.', pt: 'A sabedoria já edificou a sua casa, já lavrou as suas sete colunas;' },
      { v: 2, en: 'She has prepared her meat. She has mixed her wine. She has also set her table.', pt: 'já imolou as suas vítimas, misturou o seu vinho, e preparou a sua mesa.' },
      { v: 3, en: 'She has sent out her maidens. She cries from the highest places of the city:', pt: 'Já enviou as suas criadas a clamar sobre as alturas da cidade, dizendo:' },
      { v: 4, en: '“Whoever is simple, let him turn in here!” As for him who is void of understanding, she says to him,', pt: 'Quem é simples, volte-se para cá. Aos faltos de entendimento diz:' },
      { v: 5, en: '“Come, eat some of my bread, Drink some of the wine which I have mixed!', pt: 'Vinde, comei do meu pão, e bebei do vinho que tenho misturado.' },
      { v: 6, en: 'Leave your simple ways, and live. Walk in the way of understanding.”', pt: 'Deixai a insensatez, e vivei; e andai pelo caminho do entendimento.' },
      { v: 7, en: 'He who corrects a mocker invites insult. He who reproves a wicked man invites abuse.', pt: 'O que repreende ao escarnecedor, traz afronta sobre si; e o que censura ao ímpio, recebe a sua mancha.' },
      { v: 8, en: 'Don’t reprove a scoffer, lest he hate you. Reprove a wise man, and he will love you.', pt: 'Não repreendas ao escarnecedor, para que não te odeie; repreende ao sábio, e amar-te-á.' },
      { v: 9, en: 'Instruct a wise man, and he will be still wiser. Teach a righteous man, and he will increase in learning.', pt: 'Instrui ao sábio, e ele se fará mais, sábio; ensina ao justo, e ele crescerá em entendimento.' },
      { v: 10, en: 'The fear of Yahweh is the beginning of wisdom. The knowledge of the Holy One is understanding.', pt: 'O temor do Senhor é o princípio sabedoria; e o conhecimento do Santo é o entendimento.' },
      { v: 11, en: 'For by me your days will be multiplied. The years of your life will be increased.', pt: 'Porque por mim se multiplicam os teus dias, e anos de vida se te acrescentarão.' },
      { v: 12, en: 'If you are wise, you are wise for yourself. If you mock, you alone will bear it.', pt: 'Se fores sábio, para ti mesmo o serás; e, se fores escarnecedor, tu só o suportarás.' },
      { v: 13, en: 'The foolish woman is loud, undisciplined, and knows nothing.', pt: 'A mulher tola é alvoroçadora; é insensata, e não conhece o pudor.' },
      { v: 14, en: 'She sits at the door of her house, on a seat in the high places of the city,', pt: 'Senta-se à porta da sua casa ou numa cadeira, nas alturas da cidade,' },
      { v: 15, en: 'To call to those who pass by, who go straight on their ways,', pt: 'chamando aos que passam e seguem direitos o seu caminho:' },
      { v: 16, en: '“Whoever is simple, let him turn in here.” as for him who is void of understanding, she says to him,', pt: 'Quem é simples, volte-se para cá! E aos faltos de entendimento diz:' },
      { v: 17, en: '“Stolen water is sweet. Food eaten in secret is pleasant.”', pt: 'As águas roubadas são doces, e o pão comido às ocultas é agradável.' },
      { v: 18, en: 'But he doesn’t know that the departed spirits are there, that her guests are in the depths of Sheol.', pt: 'Mas ele não sabe que ali estão os mortos; que os seus convidados estão nas profundezas do Seol.' },
    ],
    10: [
      { v: 1, en: 'The proverbs of Solomon. A wise son makes a glad father; but a foolish son brings grief to his mother.', pt: 'Provérbios de Salomão. Um filho sábio alegra a seu pai; mas um filho insensato é a tristeza de sua mae.' },
      { v: 2, en: 'Treasures of wickedness profit nothing, but righteousness delivers from death.', pt: 'Os tesouros da impiedade de nada aproveitam; mas a justiça livra da morte.' },
      { v: 3, en: 'Yahweh will not allow the soul of the righteous to go hungry, but he thrusts away the desire of the wicked.', pt: 'O Senhor não deixa o justo passar fome; mas o desejo dos ímpios ele rechaça.' },
      { v: 4, en: 'He becomes poor who works with a lazy hand, but the hand of the diligent brings wealth.', pt: 'O que trabalha com mão remissa empobrece; mas a mão do diligente enriquece.' },
      { v: 5, en: 'He who gathers in summer is a wise son, but he who sleeps during the harvest is a son who causes shame.', pt: 'O que ajunta no verão é filho prudente; mas o que dorme na sega é filho que envergonha.' },
      { v: 6, en: 'Blessings are on the head of the righteous, but violence covers the mouth of the wicked.', pt: 'Bênçãos caem sobre a cabeça do justo; porém a boca dos ímpios esconde a violência.' },
      { v: 7, en: 'The memory of the righteous is blessed, but the name of the wicked will rot.', pt: 'A memória do justo é abençoada; mas o nome dos ímpios apodrecerá.' },
      { v: 8, en: 'The wise in heart accept commandments, but a chattering fool will fall.', pt: 'O sábio de coração aceita os mandamentos; mas o insensato palra dor cairá.' },
      { v: 9, en: 'He who walks blamelessly walks surely, but he who perverts his ways will be found out.', pt: 'Quem anda em integridade anda seguro; mas o que perverte os seus caminhos será conhecido.' },
      { v: 10, en: 'One winking with the eye causes sorrow, but a chattering fool will fall.', pt: 'O que acena com os olhos dá dores; e o insensato palrador cairá.' },
      { v: 11, en: 'The mouth of the righteous is a spring of life, but violence covers the mouth of the wicked.', pt: 'A boca do justo é manancial de vida, porém a boca dos ímpios esconde a violência.' },
      { v: 12, en: 'Hatred stirs up strife, but love covers all wrongs.', pt: 'O ódio excita contendas; mas o amor cobre todas as transgressões.' },
      { v: 13, en: 'Wisdom is found on the lips of him who has discernment, but a rod is for the back of him who is void of understanding.', pt: 'Nos lábios do entendido se acha a sabedoria; mas a vara é para as costas do que é falto de entendimento.' },
      { v: 14, en: 'Wise men lay up knowledge, but the mouth of the foolish is near ruin.', pt: 'Os sábios entesouram o conhecimento; porém a boca do insensato é uma destruição iminente.' },
      { v: 15, en: 'The rich man’s wealth is his strong city. The destruction of the poor is their poverty.', pt: 'Os bens do rico são a sua cidade forte; a ruína dos pobres é a sua pobreza.' },
      { v: 16, en: 'The labor of the righteous leads to life. The increase of the wicked leads to sin.', pt: 'O trabalho do justo conduz à vida; a renda do ímpio, para o pecado.' },
      { v: 17, en: 'He is in the way of life who heeds correction, but he who forsakes reproof leads others astray.', pt: 'O que atende à instrução está na vereda da vida; mas o que rejeita a repreensão anda errado.' },
      { v: 18, en: 'He who hides hatred has lying lips. He who utters a slander is a fool.', pt: 'O que encobre o ódio tem lábios falsos; e o que espalha a calúnia é um insensato.' },
      { v: 19, en: 'In the multitude of words there is no lack of disobedience, but he who restrains his lips does wisely.', pt: 'Na multidão de palavras não falta transgressão; mas o que refreia os seus lábios é prudente.' },
      { v: 20, en: 'The tongue of the righteous is like choice silver. The heart of the wicked is of little worth.', pt: 'A língua do justo é prata escolhida; o coração dos ímpios é de pouco valor.' },
      { v: 21, en: 'The lips of the righteous feed many, but the foolish die for lack of understanding.', pt: 'Os lábios do justo apascentam a muitos; mas os insensatos, por falta de entendimento, morrem.' },
      { v: 22, en: 'Yahweh’s blessing brings wealth, and he adds no trouble to it.', pt: 'A bênção do Senhor é que enriquece; e ele não a faz seguir de dor alguma.' },
      { v: 23, en: 'It is a fool’s pleasure to do wickedness, but wisdom is a man of understanding’s pleasure.', pt: 'E um divertimento para o insensato o praticar a iniqüidade; mas a conduta sábia é o prazer do homem entendido.' },
      { v: 24, en: 'What the wicked fear, will overtake them, but the desire of the righteous will be granted.', pt: 'O que o ímpio teme, isso virá sobre ele; mas aos justos se lhes concederá o seu desejo.' },
      { v: 25, en: 'When the whirlwind passes, the wicked is no more; but the righteous stand firm forever.', pt: 'Como passa a tempestade, assim desaparece o impio; mas o justo tem fundamentos eternos.' },
      { v: 26, en: 'As vinegar to the teeth, and as smoke to the eyes, so is the sluggard to those who send him.', pt: 'Como vinagre para os dentes, como fumaça para os olhos, assim é o preguiçoso para aqueles que o mandam.' },
      { v: 27, en: 'The fear of Yahweh prolongs days, but the years of the wicked shall be shortened.', pt: 'O temor do Senhor aumenta os dias; mas os anos os impios serão abreviados.' },
      { v: 28, en: 'The prospect of the righteous is joy, but the hope of the wicked will perish.', pt: 'A esperança dos justos é alegria; mas a expectação dos ímpios perecerá.' },
      { v: 29, en: 'The way of Yahweh is a stronghold to the upright, but it is a destruction to the workers of iniquity.', pt: 'O caminho do Senhor é fortaleza para os retos; mas é destruição para os que praticam a iniqüidade.' },
      { v: 30, en: 'The righteous will never be removed, but the wicked will not dwell in the land.', pt: 'O justo nunca será abalado; mas os ímpios não habitarão a terra.' },
      { v: 31, en: 'The mouth of the righteous produces wisdom, but the perverse tongue will be cut off.', pt: 'A boca do justo produz sabedoria; porém a língua perversa será desarraigada.' },
      { v: 32, en: 'The lips of the righteous know what is acceptable, but the mouth of the wicked is perverse.', pt: 'Os lábios do justo sabem o que agrada; porém a boca dos ímpios fala perversidades.' },
    ],
    11: [
      { v: 1, en: 'A false balance is an abomination to Yahweh, but accurate weights are his delight.', pt: 'A balança enganosa é abominação para o Senhor; mas o peso justo é o seu prazer.' },
      { v: 2, en: 'When pride comes, then comes shame, but with humility comes wisdom.', pt: 'Quando vem a soberba, então vem a desonra; mas com os humildes está a sabedoria.' },
      { v: 3, en: 'The integrity of the upright shall guide them, but the perverseness of the treacherous shall destroy them.', pt: 'A integridade dos retos os guia; porém a perversidade dos desleais os destrói.' },
      { v: 4, en: 'Riches don’t profit in the day of wrath, but righteousness delivers from death.', pt: 'De nada aproveitam as riquezas no dia da ira; porém a justiça livra da morte.' },
      { v: 5, en: 'The righteousness of the blameless will direct his way, but the wicked shall fall by his own wickedness.', pt: 'A justiça dos perfeitos endireita o seu caminho; mas o ímpio cai pela sua impiedade.' },
      { v: 6, en: 'The righteousness of the upright shall deliver them, but the unfaithful will be trapped by evil desires.', pt: 'A justiça dos retos os livra; mas os traiçoeiros são apanhados nas, suas próprias cobiças.' },
      { v: 7, en: 'When a wicked man dies, hope perishes, and expectation of power comes to nothing.', pt: 'Morrendo o ímpio, perece a sua esperança; e a expectativa da iniqüidade.' },
      { v: 8, en: 'A righteous person is delivered out of trouble, and the wicked takes his place.', pt: 'O justo é libertado da angústia; e o ímpio fica em seu lugar.' },
      { v: 9, en: 'With his mouth the godless man destroys his neighbor, but the righteous will be delivered through knowledge.', pt: 'O hipócrita com a boca arruína o seu proximo; mas os justos são libertados pelo conhecimento.' },
      { v: 10, en: 'When it goes well with the righteous, the city rejoices. When the wicked perish, there is shouting.', pt: 'Quando os justos prosperam, exulta a cidade; e quando perecem os ímpios, há júbilo.' },
      { v: 11, en: 'By the blessing of the upright, the city is exalted, but it is overthrown by the mouth of the wicked.', pt: 'Pela bênção dos retos se exalta a cidade; mas pela boca dos ímpios é derrubada.' },
      { v: 12, en: 'One who despises his neighbor is void of wisdom, but a man of understanding holds his peace.', pt: 'Quem despreza o seu próximo é falto de senso; mas o homem de entendimento se cala.' },
      { v: 13, en: 'One who brings gossip betrays a confidence, but one who is of a trustworthy spirit is one who keeps a secret.', pt: 'O que anda mexericando revela segredos; mas o fiel de espírito encobre o negócio.' },
      { v: 14, en: 'Where there is no wise guidance, the nation falls, but in the multitude of counselors there is victory.', pt: 'Quando não há sábia direção, o povo cai; mas na multidão de conselheiros há segurança.' },
      { v: 15, en: 'He who is collateral for a stranger will suffer for it, but he who refuses pledges of collateral is secure.', pt: 'Decerto sofrerá prejuízo aquele que fica por fiador do estranho; mas o que aborrece a fiança estará seguro.' },
      { v: 16, en: 'A gracious woman obtains honor, but violent men obtain riches.', pt: 'A mulher aprazível obtém honra, e os homens violentos obtêm riquezas.' },
      { v: 17, en: 'The merciful man does good to his own soul, but he who is cruel troubles his own flesh.', pt: 'O homem bondoso faz bem à sua, própria alma; mas o cruel faz mal a si mesmo.' },
      { v: 18, en: 'Wicked people earn deceitful wages, but one who sows righteousness reaps a sure reward.', pt: 'O ímpio recebe um salário ilusório; mas o que semeia justiça recebe galardão seguro.' },
      { v: 19, en: 'He who is truly righteous gets life. He who pursues evil gets death.', pt: 'Quem é fiel na retidão encaminha, para a vida, e aquele que segue o mal encontra a morte.' },
      { v: 20, en: 'Those who are perverse in heart are an abomination to Yahweh, but those whose ways are blameless are his delight.', pt: 'Abominação para o Senhor são os perversos de coração; mas os que são perfeitos em seu caminho são o seu deleite.' },
      { v: 21, en: 'Most certainly, the evil man will not be unpunished, but the offspring of the righteous will be delivered.', pt: 'Decerto o homem mau não ficará sem castigo; porém a descendência dos justos será livre.' },
      { v: 22, en: 'Like a gold ring in a pig’s snout, is a beautiful woman who lacks discretion.', pt: 'Como jóia de ouro em focinho de porca, assim é a mulher formosa que se aparta da discrição.' },
      { v: 23, en: 'The desire of the righteous is only good. The expectation of the wicked is wrath.', pt: 'O desejo dos justos é somente o bem; porém a expectativa dos ímpios é a ira.' },
      { v: 24, en: 'There is one who scatters, and increases yet more. There is one who withholds more than is appropriate, but gains poverty.', pt: 'Um dá liberalmente, e se torna mais rico; outro retém mais do que é justo, e se empobrece.' },
      { v: 25, en: 'The liberal soul shall be made fat. He who waters shall be watered also himself.', pt: 'A alma generosa prosperará, e o que regar também será regado.' },
      { v: 26, en: 'People curse someone who withholds grain, but blessing will be on the head of him who sells it.', pt: 'Ao que retém o trigo o povo o amaldiçoa; mas bênção haverá sobre a cabeça do que o vende.' },
      { v: 27, en: 'He who diligently seeks good seeks favor, but he who searches after evil, it shall come to him.', pt: 'O que busca diligentemente o bem, busca favor; mas ao que procura o mal, este lhe sobrevirá.' },
      { v: 28, en: 'He who trusts in his riches will fall, but the righteous shall flourish as the green leaf.', pt: 'Aquele que confia nas suas riquezas, cairá; mas os justos reverdecerão como a folhagem.' },
      { v: 29, en: 'He who troubles his own house shall inherit the wind. The foolish shall be servant to the wise of heart.', pt: 'O que perturba a sua casa herdará o vento; e o insensato será servo do entendido de coração.' },
      { v: 30, en: 'The fruit of the righteous is a tree of life. He who is wise wins souls.', pt: 'O fruto do justo é árvore de vida; e o que ganha almas sábio é.' },
      { v: 31, en: 'Behold, the righteous shall be repaid in the earth; how much more the wicked and the sinner!', pt: 'Eis que o justo é castigado na terra; quanto mais o ímpio e o pecador!' },
    ],
    12: [
      { v: 1, en: 'Whoever loves correction loves knowledge, but he who hates reproof is stupid.', pt: 'O que ama a correção ama o conhecimento; mas o que aborrece a repreensão é insensato.' },
      { v: 2, en: 'A good man shall obtain favor from Yahweh, but he will condemn a man of wicked plans.', pt: 'O homem de bem alcançará o favor do Senhor; mas ao homem de perversos desígnios ele condenará.' },
      { v: 3, en: 'A man shall not be established by wickedness, but the root of the righteous shall not be moved.', pt: 'O homem não se estabelece pela impiedade; a raiz dos justos, porém, nunca será, removida.' },
      { v: 4, en: 'A worthy woman is the crown of her husband, but a disgraceful wife is as rottenness in his bones.', pt: 'A mulher virtuosa é a coroa do seu marido; porém a que procede vergonhosamente é como apodrecimento nos seus ossos.' },
      { v: 5, en: 'The thoughts of the righteous are just, but the advice of the wicked is deceitful.', pt: 'Os pensamentos do justo são retos; mas os conselhos do ímpio são falsos.' },
      { v: 6, en: 'The words of the wicked are about lying in wait for blood, but the speech of the upright rescues them.', pt: 'As palavras dos ímpios são emboscadas para derramarem sangue; a boca dos retos, porém, os livrará.' },
      { v: 7, en: 'The wicked are overthrown, and are no more, but the house of the righteous shall stand.', pt: 'Transtornados serão os ímpios, e não serão mais; porém a casa dos justos permanecerá.' },
      { v: 8, en: 'A man shall be commended according to his wisdom, but he who has a warped mind shall be despised.', pt: 'Segundo o seu entendimento é louvado o homem; mas o perverso decoração é desprezado.' },
      { v: 9, en: 'Better is he who is little know, and has a servant, than he who honors himself, and lacks bread.', pt: 'Melhor é o que é estimado em pouco e tem servo, do que quem se honra a si mesmo e tem falta de pão.' },
      { v: 10, en: 'A righteous man respects the life of his animal, but the tender mercies of the wicked are cruel.', pt: 'O justo olha pela vida dos seus animais; porém as entranhas dos ímpios são crueis.' },
      { v: 11, en: 'He who tills his land shall have plenty of bread, but he who chases fantasies is void of understanding.', pt: 'O que lavra a sua terra se fartará de pão; mas o que segue os ociosos é falto de entendimento.' },
      { v: 12, en: 'The wicked desires the plunder of evil men, but the root of the righteous flourishes.', pt: 'Deseja o ímpio o despojo dos maus; porém a raiz dos justos produz o seu próprio fruto.' },
      { v: 13, en: 'An evil man is trapped by sinfulness of lips, but the righteous shall come out of trouble.', pt: 'Pela transgressão dos lábios se enlaça o mau; mas o justo escapa da angústia.' },
      { v: 14, en: 'A man shall be satisfied with good by the fruit of his mouth. The work of a man’s hands shall be rewarded to him.', pt: 'Do fruto das suas palavras o homem se farta de bem; e das obras das suas mãos se lhe retribui.' },
      { v: 15, en: 'The way of a fool is right in his own eyes, but he who is wise listens to counsel.', pt: 'O caminho do insensato é reto aos seus olhos; mas o que dá ouvidos ao conselho é sábio.' },
      { v: 16, en: 'A fool shows his annoyance the same day, but one who overlooks an insult is prudent.', pt: 'A ira do insensato logo se revela; mas o prudente encobre a afronta.' },
      { v: 17, en: 'He who is truthful testifies honestly, but a false witness lies.', pt: 'Quem fala a verdade manifesta a justiça; porém a testemunha falsa produz a fraude.' },
      { v: 18, en: 'There is one who speaks rashly like the piercing of a sword, but the tongue of the wise heals.', pt: 'Há palrador cujas palavras ferem como espada; porém a língua dos sábios traz saúde.' },
      { v: 19, en: 'Truth’s lips will be established forever, but a lying tongue is only momentary.', pt: 'O lábio veraz permanece para sempre; mas a língua mentirosa dura só um momento.' },
      { v: 20, en: 'Deceit is in the heart of those who plot evil, but joy comes to the promoters of peace.', pt: 'Engano há no coração dos que maquinam o mal; mas há gozo para os que aconselham a paz.' },
      { v: 21, en: 'No mischief shall happen to the righteous, but the wicked shall be filled with evil.', pt: 'Nenhuma desgraça sobrevém ao justo; mas os ímpios ficam cheios de males.' },
      { v: 22, en: 'Lying lips are an abomination to Yahweh, but those who do the truth are his delight.', pt: 'Os lábios mentirosos são abomináveis ao Senhor; mas os que praticam a verdade são o seu deleite.' },
      { v: 23, en: 'A prudent man keeps his knowledge, but the hearts of fools proclaim foolishness.', pt: 'O homem prudente encobre o conhecimento; mas o coração dos tolos proclama a estultícia.' },
      { v: 24, en: 'The hands of the diligent ones shall rule, but laziness ends in slave labor.', pt: 'A mão dos diligentes dominará; mas o indolente será tributário servil.' },
      { v: 25, en: 'Anxiety in a man’s heart weighs it down, but a kind word makes it glad.', pt: 'A ansiedade no coração do homem o abate; mas uma boa palavra o alegra.' },
      { v: 26, en: 'A righteous person is cautious in friendship, but the way of the wicked leads them astray.', pt: 'O justo é um guia para o seu próximo; mas o caminho dos ímpios os faz errar.' },
      { v: 27, en: 'The slothful man doesn’t roast his game, but the possessions of diligent men are prized.', pt: 'O preguiçoso não apanha a sua caça; mas o bem precioso do homem é para o diligente.' },
      { v: 28, en: 'In the way of righteousness is life; in its path there is no death.', pt: 'Na vereda da justiça está a vida; e no seu caminho não há morte.' },
    ],
    13: [
      { v: 1, en: 'A wise son listens to his father’s instruction, but a scoffer doesn’t listen to rebuke.', pt: 'O filho sábio ouve a instrução do pai; mas o escarnecedor não escuta a repreensão.' },
      { v: 2, en: 'By the fruit of his lips, a man enjoys good things; but the unfaithful crave violence.', pt: 'Do fruto da boca o homem come o bem; mas o apetite dos prevaricadores alimenta-se da violência.' },
      { v: 3, en: 'He who guards his mouth guards his soul. One who opens wide his lips comes to ruin.', pt: 'O que guarda a sua boca preserva a sua vida; mas o que muito abre os seus lábios traz sobre si a ruína.' },
      { v: 4, en: 'The soul of the sluggard desires, and has nothing, but the desire of the diligent shall be fully satisfied.', pt: 'O preguiçoso deseja, e coisa nenhuma alcança; mas o desejo do diligente será satisfeito.' },
      { v: 5, en: 'A righteous man hates lies, but a wicked man brings shame and disgrace.', pt: 'O justo odeia a palavra mentirosa, mas o ímpio se faz odioso e se cobre de vergonha.' },
      { v: 6, en: 'Righteousness guards the way of integrity, but wickedness overthrows the sinner.', pt: 'A justiça guarda ao que é reto no seu caminho; mas a perversidade transtorna o pecador.' },
      { v: 7, en: 'There are some who pretend to be rich, yet have nothing. There are some who pretend to be poor, yet have great wealth.', pt: 'Há quem se faça rico, não tendo coisa alguma; e quem se faça pobre, tendo grande riqueza.' },
      { v: 8, en: 'The ransom of a man’s life is his riches, but the poor hear no threats.', pt: 'O resgate da vida do homem são as suas riquezas; mas o pobre não tem meio de se resgatar.' },
      { v: 9, en: 'The light of the righteous shines brightly, but the lamp of the wicked is snuffed out.', pt: 'A luz dos justos alegra; porem a lâmpada dos impios se apagará.' },
      { v: 10, en: 'Pride only breeds quarrels, but with ones who take advice is wisdom.', pt: 'Da soberba só provém a contenda; mas com os que se aconselham se acha a sabedoria.' },
      { v: 11, en: 'Wealth gained dishonestly dwindles away, but he who gathers by hand makes it grow.', pt: 'A riqueza adquirida às pressas diminuira; mas quem a ajunta pouco a pouco terá aumento.' },
      { v: 12, en: 'Hope deferred makes the heart sick, but when longing is fulfilled, it is a tree of life.', pt: 'A esperança adiada entristece o coração; mas o desejo cumprido é árvore devida.' },
      { v: 13, en: 'Whoever despises instruction will pay for it, but he who respects a command will be rewarded.', pt: 'O que despreza a palavra traz sobre si a destruição; mas o que teme o mandamento será galardoado.' },
      { v: 14, en: 'The teaching of the wise is a spring of life, to turn from the snares of death.', pt: 'O ensino do sábio é uma fonte devida para desviar dos laços da morte.' },
      { v: 15, en: 'Good understanding wins favor; but the way of the unfaithful is hard.', pt: 'O bom senso alcança favor; mas o caminho dos prevaricadores é aspero:' },
      { v: 16, en: 'Every prudent man acts from knowledge, but a fool exposes folly.', pt: 'Em tudo o homem prudente procede com conhecimento; mas o tolo espraia a sua insensatez.' },
      { v: 17, en: 'A wicked messenger falls into trouble, but a trustworthy envoy gains healing.', pt: 'O mensageiro perverso faz cair no mal; mas o embaixador fiel traz saúde.' },
      { v: 18, en: 'Poverty and shame come to him who refuses discipline, but he who heeds correction shall be honored.', pt: 'Pobreza e afronta virão ao que rejeita a correção; mas o que guarda a repreensão será honrado.' },
      { v: 19, en: 'Longing fulfilled is sweet to the soul, but fools detest turning from evil.', pt: 'O desejo que se cumpre deleita a alma; mas apartar-se do ma e abominação para os tolos.' },
      { v: 20, en: 'One who walks with wise men grows wise, but a companion of fools suffers harm.', pt: 'Quem anda com os sábios será sábio; mas o companheiro dos tolos sofre aflição.' },
      { v: 21, en: 'Misfortune pursues sinners, but prosperity rewards the righteous.', pt: 'O mal persegue os pecadores; mas os justos são galardoados com o bem.' },
      { v: 22, en: 'A good man leaves an inheritance to his children’s children, but the wealth of the sinner is stored for the righteous.', pt: 'O homem de bem deixa uma herança aos filhos de seus filhos; a riqueza do pecador, porém, é reservada para o justo.' },
      { v: 23, en: 'An abundance of food is in poor people’s fields, but injustice sweeps it away.', pt: 'Abundância de mantimento há, na lavoura do pobre; mas se perde por falta de juízo.' },
      { v: 24, en: 'One who spares the rod hates his son, but one who loves him is careful to discipline him.', pt: 'Aquele que poupa a vara aborrece a seu filho; mas quem o ama, a seu tempo o castiga.' },
      { v: 25, en: 'The righteous one eats to the satisfying of his soul, but the belly of the wicked goes hungry.', pt: 'O justo come e fica satisfeito; mas o apetite dos ímpios nunca se satisfaz.' },
    ],
    14: [
      { v: 1, en: 'Every wise woman builds her house, but the foolish one tears it down with her own hands.', pt: 'Toda mulher sábia edifica a sua casa; a insensata, porém, derruba-a com as suas mãos.' },
      { v: 2, en: 'He who walks in his uprightness fears Yahweh, but he who is perverse in his ways despises him.', pt: 'Quem anda na sua retidão teme ao Senhor; mas aquele que é perverso nos seus caminhos despreza-o.' },
      { v: 3, en: 'The fool’s talk brings a rod to his back, but the lips of the wise protect them.', pt: 'Na boca do tolo está a vara da soberba, mas os lábios do sábio preservá-lo-ão.' },
      { v: 4, en: 'Where no oxen are, the crib is clean, but much increase is by the strength of the ox.', pt: 'Onde não há bois, a manjedoura está vazia; mas pela força do boi há abundância de colheitas.' },
      { v: 5, en: 'A truthful witness will not lie, but a false witness pours out lies.', pt: 'A testemunha verdadeira não mentirá; a testemunha falsa, porém, se desboca em mentiras.' },
      { v: 6, en: 'A scoffer seeks wisdom, and doesn’t find it, but knowledge comes easily to a discerning person.', pt: 'O escarnecedor busca sabedoria, e não a encontra; mas para o prudente o conhecimento é fácil.' },
      { v: 7, en: 'Stay away from a foolish man, for you won’t find knowledge on his lips.', pt: 'Vai-te da presença do homem insensato, pois nele não acharás palavras de ciência.' },
      { v: 8, en: 'The wisdom of the prudent is to think about his way, but the folly of fools is deceit.', pt: 'A sabedoria do prudente é entender o seu caminho; porém a estultícia dos tolos é enganar.' },
      { v: 9, en: 'Fools mock at making atonement for sins, but among the upright there is good will.', pt: 'A culpa zomba dos insensatos; mas os retos têm o favor de Deus.' },
      { v: 10, en: 'The heart knows its own bitterness and joy; he will not share these with a stranger.', pt: 'O coração conhece a sua própria amargura; e o estranho não participa da sua alegria.' },
      { v: 11, en: 'The house of the wicked will be overthrown, but the tent of the upright will flourish.', pt: 'A casa dos ímpios se desfará; porém a tenda dos retos florescerá.' },
      { v: 12, en: 'There is a way which seems right to a man, but in the end it leads to death.', pt: 'Há um caminho que ao homem parece direito, mas o fim dele conduz à morte.' },
      { v: 13, en: 'Even in laughter the heart may be sorrowful, and mirth may end in heaviness.', pt: 'Até no riso terá dor o coração; e o fim da alegria é tristeza.' },
      { v: 14, en: 'The unfaithful will be repaid for his own ways; likewise a good man will be rewarded for his ways.', pt: 'Dos seus próprios caminhos se fartará o infiel de coração, como também o homem bom se contentará dos seus.' },
      { v: 15, en: 'A simple man believes everything, but the prudent man carefully considers his ways.', pt: 'O simples dá crédito a tudo; mas o prudente atenta para os seus passos.' },
      { v: 16, en: 'A wise man fears and shuns evil, but the fool is hot headed and reckless.', pt: 'O sábio teme e desvia-se do mal, mas o tolo é arrogante e dá-se por seguro.' },
      { v: 17, en: 'He who is quick to become angry will commit folly, and a crafty man is hated.', pt: 'Quem facilmente se ira fará doidices; mas o homem discreto é paciente;' },
      { v: 18, en: 'The simple inherit folly, but the prudent are crowned with knowledge.', pt: 'Os simples herdam a estultícia; mas os prudentes se coroam de conhecimento.' },
      { v: 19, en: 'The evil bow down before the good, and the wicked at the gates of the righteous.', pt: 'Os maus inclinam-se perante os bons; e os ímpios diante das portas dos justos.' },
      { v: 20, en: 'The poor person is shunned even by his own neighbor, but the rich person has many friends.', pt: 'O pobre é odiado até pelo seu vizinho; mas os amigos dos ricos são muitos.' },
      { v: 21, en: 'He who despises his neighbor sins, but blessed is he who has pity on the poor.', pt: 'O que despreza ao seu vizinho peca; mas feliz é aquele que se compadece dos pobres.' },
      { v: 22, en: 'Don’t they go astray who plot evil? But love and faithfulness belong to those who plan good.', pt: 'Porventura não erram os que maquinam o mal? mas há beneficência e fidelidade para os que planejam o bem.' },
      { v: 23, en: 'In all hard work there is profit, but the talk of the lips leads only to poverty.', pt: 'Em todo trabalho há proveito; meras palavras, porém, só encaminham para a penúria.' },
      { v: 24, en: 'The crown of the wise is their riches, but the folly of fools crowns them with folly.', pt: 'A coroa dos sábios é a sua riqueza; porém a estultícia dos tolos não passa de estultícia.' },
      { v: 25, en: 'A truthful witness saves souls, but a false witness is deceitful.', pt: 'A testemunha verdadeira livra as almas; mas o que fala mentiras é traidor.' },
      { v: 26, en: 'In the fear of Yahweh is a secure fortress, and he will be a refuge for his children.', pt: 'No temor do Senhor há firme confiança; e os seus filhos terão um lugar de refúgio.' },
      { v: 27, en: 'The fear of Yahweh is a fountain of life, turning people from the snares of death.', pt: 'O temor do Senhor é uma fonte de vida, para o homem se desviar dos laços da morte.' },
      { v: 28, en: 'In the multitude of people is the king’s glory, but in the lack of people is the destruction of the prince.', pt: 'Na multidão do povo está a glória do rei; mas na falta de povo está a ruína do príncipe.' },
      { v: 29, en: 'He who is slow to anger has great understanding, but he who has a quick temper displays folly.', pt: 'Quem é tardio em irar-se é grande em entendimento; mas o que é de ânimo precipitado exalta a loucura.' },
      { v: 30, en: 'The life of the body is a heart at peace, but envy rots the bones.', pt: 'O coração tranqüilo é a vida da carne; a inveja, porém, é a podridão dos ossos.' },
      { v: 31, en: 'He who oppresses the poor shows contempt for his Maker, but he who is kind to the needy honors him.', pt: 'O que oprime ao pobre insulta ao seu Criador; mas honra-o aquele que se compadece do necessitado.' },
      { v: 32, en: 'The wicked is brought down in his calamity, but in death, the righteous has a refuge.', pt: 'O ímpio é derrubado pela sua malícia; mas o justo até na sua morte acha refúgio.' },
      { v: 33, en: 'Wisdom rests in the heart of one who has understanding, and is even made known in the inward part of fools.', pt: 'No coração do prudente repousa a sabedoria; mas no coração dos tolos não é conhecida.' },
      { v: 34, en: 'Righteousness exalts a nation, but sin is a disgrace to any people.', pt: 'A justiça exalta as nações; mas o pecado é o opróbrio dos povos.' },
      { v: 35, en: 'The king’s favor is toward a servant who deals wisely, but his wrath is toward one who causes shame.', pt: 'O favor do rei é concedido ao servo que procede sabiamente; mas sobre o que procede indignamente cairá o seu furor.' },
    ],
    15: [
      { v: 1, en: 'A gentle answer turns away wrath, but a harsh word stirs up anger.', pt: 'A resposta branda desvia o furor, mas a palavra dura suscita a ira.' },
      { v: 2, en: 'The tongue of the wise commends knowledge, but the mouth of fools gush out folly.', pt: 'A língua dos sábios destila o conhecimento; porém a boca dos tolos derrama a estultícia.' },
      { v: 3, en: 'Yahweh’s eyes are everywhere, keeping watch on the evil and the good.', pt: 'Os olhos do Senhor estão em todo lugar, vigiando os maus e os bons.' },
      { v: 4, en: 'A gentle tongue is a tree of life, but deceit in it crushes the spirit.', pt: 'Uma língua suave é árvore de vida; mas a língua perversa quebranta o espírito.' },
      { v: 5, en: 'A fool despises his father’s correction, but he who heeds reproof shows prudence.', pt: 'O insensato despreza a correção e seu pai; mas o que atende à admoestação prudentemente se haverá.' },
      { v: 6, en: 'In the house of the righteous is much treasure, but the income of the wicked brings trouble.', pt: 'Na casa do justo há um grande tesouro; mas nos lucros do ímpio há perturbação.' },
      { v: 7, en: 'The lips of the wise spread knowledge; not so with the heart of fools.', pt: 'Os lábios dos sábios difundem conhecimento; mas não o faz o coração dos tolos.' },
      { v: 8, en: 'The sacrifice made by the wicked is an abomination to Yahweh, but the prayer of the upright is his delight.', pt: 'O sacrifício dos ímpios é abominável ao Senhor; mas a oração dos retos lhe é agradável.' },
      { v: 9, en: 'The way of the wicked is an abomination to Yahweh, but he loves him who follows after righteousness.', pt: 'O caminho do ímpio é abominável ao Senhor; mas ele ama ao que segue a justiça.' },
      { v: 10, en: 'There is stern discipline for one who forsakes the way: whoever hates reproof shall die.', pt: 'Há disciplina severa para o que abandona a vereda; e o que aborrece a repreensão morrerá.' },
      { v: 11, en: 'Sheol and Abaddon are before Yahweh— how much more then the hearts of the children of men!', pt: 'O Seol e o Abadom estão abertos perante o Senhor; quanto mais o coração dos filhos dos homens!' },
      { v: 12, en: 'A scoffer doesn’t love to be reproved; he will not go to the wise.', pt: 'O escarnecedor não gosta daquele que o repreende; não irá ter com os sábios.' },
      { v: 13, en: 'A glad heart makes a cheerful face; but an aching heart breaks the spirit.', pt: 'O coração alegre aformoseia o rosto; mas pela dor do coração o espírito se abate.' },
      { v: 14, en: 'The heart of one who has understanding seeks knowledge, but the mouths of fools feed on folly.', pt: 'O coração do inteligente busca o conhecimento; mas a boca dos tolos se apascenta de estultícia.' },
      { v: 15, en: 'All the days of the afflicted are wretched, but one who has a cheerful heart enjoys a continual feast.', pt: 'Todos os dias do aflito são maus; mas o coração contente tem um banquete contínuo.' },
      { v: 16, en: 'Better is little, with the fear of Yahweh, than great treasure with trouble.', pt: 'Melhor é o pouco com o temor do Senhor, do que um grande tesouro, e com ele a inquietação.' },
      { v: 17, en: 'Better is a dinner of herbs, where love is, than a fattened calf with hatred.', pt: 'Melhor é um prato de hortaliça, onde há amor, do que o boi gordo, e com ele o ódio.' },
      { v: 18, en: 'A wrathful man stirs up contention, but one who is slow to anger appeases strife.', pt: 'O homem iracundo suscita contendas; mas o longânimo apazigua a luta.' },
      { v: 19, en: 'The way of the sluggard is like a thorn patch, but the path of the upright is a highway.', pt: 'O caminho do preguiçoso é como a sebe de espinhos; porém a vereda dos justos é uma estrada real.' },
      { v: 20, en: 'A wise son makes a father glad, but a foolish man despises his mother.', pt: 'O filho sábio alegra a seu pai; mas o homem insensato despreza a sua mãe.' },
      { v: 21, en: 'Folly is joy to one who is void of wisdom, but a man of understanding keeps his way straight.', pt: 'A estultícia é alegria para o insensato; mas o homem de entendimento anda retamente.' },
      { v: 22, en: 'Where there is no counsel, plans fail; but in a multitude of counselors they are established.', pt: 'Onde não há conselho, frustram-se os projetos; mas com a multidão de conselheiros se estabelecem.' },
      { v: 23, en: 'Joy comes to a man with the reply of his mouth. How good is a word at the right time!', pt: 'O homem alegra-se em dar uma resposta adequada; e a palavra a seu tempo quão boa é!' },
      { v: 24, en: 'The path of life leads upward for the wise, to keep him from going downward to Sheol.', pt: 'Para o sábio o caminho da vida é para cima, a fim de que ele se desvie do Seol que é em baixo.' },
      { v: 25, en: 'Yahweh will uproot the house of the proud, but he will keep the widow’s borders intact.', pt: 'O Senhor desarraiga a casa dos soberbos, mas estabelece a herança da viúva.' },
      { v: 26, en: 'Yahweh detests the thoughts of the wicked, but the thoughts of the pure are pleasing.', pt: 'Os desígnios dos maus são abominação para o Senhor; mas as palavras dos limpos lhe são aprazíveis.' },
      { v: 27, en: 'He who is greedy for gain troubles his own house, but he who hates bribes will live.', pt: 'O que se dá à cobiça perturba a sua própria casa; mas o que aborrece a peita viverá.' },
      { v: 28, en: 'The heart of the righteous weighs answers, but the mouth of the wicked gushes out evil.', pt: 'O coração do justo medita no que há de responder; mas a boca dos ímpios derrama coisas más.' },
      { v: 29, en: 'Yahweh is far from the wicked, but he hears the prayer of the righteous.', pt: 'Longe está o Senhor dos ímpios, mas ouve a oração dos justos.' },
      { v: 30, en: 'The light of the eyes rejoices the heart. Good news gives health to the bones.', pt: 'A luz dos olhos alegra o coração, e boas-novas engordam os ossos.' },
      { v: 31, en: 'The ear that listens to reproof lives, and will be at home among the wise.', pt: 'O ouvido que escuta a advertência da vida terá a sua morada entre os sábios.' },
      { v: 32, en: 'He who refuses correction despises his own soul, but he who listens to reproof gets understanding.', pt: 'Quem rejeita a correção menospreza a sua alma; mas aquele que escuta a advertência adquire entendimento.' },
      { v: 33, en: 'The fear of Yahweh teaches wisdom. Before honor is humility.', pt: 'O temor do Senhor é a instrução da sabedoria; e adiante da honra vai a humildade.' },
    ],
    16: [
      { v: 1, en: 'The plans of the heart belong to man, but the answer of the tongue is from Yahweh.', pt: 'Ao homem pertencem os planos do coração; mas a resposta da língua é do Senhor.' },
      { v: 2, en: 'All the ways of a man are clean in his own eyes; but Yahweh weighs the motives.', pt: 'Todos os caminhos do homem são limpos aos seus olhos; mas o Senhor pesa os espíritos.' },
      { v: 3, en: 'Commit your deeds to Yahweh, and your plans shall succeed.', pt: 'Entrega ao Senhor as tuas obras, e teus desígnios serão estabelecidos.' },
      { v: 4, en: 'Yahweh has made everything for its own end— yes, even the wicked for the day of evil.', pt: 'O Senhor fez tudo para um fim; sim, até o ímpio para o dia do mal.' },
      { v: 5, en: 'Everyone who is proud in heart is an abomination to Yahweh: they shall certainly not be unpunished.', pt: 'Todo homem arrogante é abominação ao Senhor; certamente não ficará impune.' },
      { v: 6, en: 'By mercy and truth iniquity is atoned for. By the fear of Yahweh men depart from evil.', pt: 'Pela misericórdia e pela verdade expia-se a iniqüidade; e pelo temor do Senhor os homens se desviam do mal.' },
      { v: 7, en: 'When a man’s ways please Yahweh, he makes even his enemies to be at peace with him.', pt: 'Quando os caminhos do homem agradam ao Senhor, faz que até os seus inimigos tenham paz com ele.' },
      { v: 8, en: 'Better is a little with righteousness, than great revenues with injustice.', pt: 'Melhor é o pouco com justiça, do que grandes rendas com injustiça.' },
      { v: 9, en: 'A man’s heart plans his course, but Yahweh directs his steps.', pt: 'O coração do homem propõe o seu caminho; mas o Senhor lhe dirige os passos.' },
      { v: 10, en: 'Inspired judgments are on the lips of the king. He shall not betray his mouth.', pt: 'Nos lábios do rei acham-se oráculos; em juízo a sua boca não prevarica.' },
      { v: 11, en: 'Honest balances and scales are Yahweh’s; all the weights in the bag are his work.', pt: 'O peso e a balança justos são do Senhor; obra sua são todos os pesos da bolsa.' },
      { v: 12, en: 'It is an abomination for kings to do wrong, for the throne is established by righteousness.', pt: 'Abominação é para os reis o praticarem a impiedade; porque com justiça se estabelece o trono.' },
      { v: 13, en: 'Righteous lips are the delight of kings. They value one who speaks the truth.', pt: 'Lábios justos são o prazer dos reis; e eles amam aquele que fala coisas retas.' },
      { v: 14, en: 'The king’s wrath is a messenger of death, but a wise man will pacify it.', pt: 'O furor do rei é mensageiro da morte; mas o homem sábio o aplacará.' },
      { v: 15, en: 'In the light of the king’s face is life. His favor is like a cloud of the spring rain.', pt: 'Na luz do semblante do rei está a vida; e o seu favor é como a nuvem de chuva serôdia.' },
      { v: 16, en: 'How much better it is to get wisdom than gold! Yes, to get understanding is to be chosen rather than silver.', pt: 'Quanto melhor é adquirir a sabedoria do que o ouro! e quanto mais excelente é escolher o entendimento do que a prata!' },
      { v: 17, en: 'The highway of the upright is to depart from evil. He who keeps his way preserves his soul.', pt: 'A estrada dos retos desvia-se do mal; o que guarda o seu caminho preserva a sua vida.' },
      { v: 18, en: 'Pride goes before destruction, and a haughty spirit before a fall.', pt: 'A soberba precede a destruição, e a altivez do espírito precede a queda.' },
      { v: 19, en: 'It is better to be of a lowly spirit with the poor, than to divide the plunder with the proud.', pt: 'Melhor é ser humilde de espírito com os mansos, do que repartir o despojo com os soberbos.' },
      { v: 20, en: 'He who heeds the Word finds prosperity. Whoever trusts in Yahweh is blessed.', pt: 'O que atenta prudentemente para a palavra prosperará; e feliz é aquele que confia no Senhor.' },
      { v: 21, en: 'The wise in heart shall be called prudent. Pleasantness of the lips promotes instruction.', pt: 'O sábio de coração será chamado prudente; e a doçura dos lábios aumenta o saber.' },
      { v: 22, en: 'Understanding is a fountain of life to one who has it, but the punishment of fools is their folly.', pt: 'O entendimento, para aquele que o possui, é uma fonte de vida, porém a estultícia é o castigo dos insensatos.' },
      { v: 23, en: 'The heart of the wise instructs his mouth, and adds learning to his lips.', pt: 'O coração do sábio instrui a sua boca, e aumenta o saber nos seus lábios.' },
      { v: 24, en: 'Pleasant words are a honeycomb, sweet to the soul, and health to the bones.', pt: 'Palavras suaves são como favos de mel, doçura para a alma e saúde para o corpo.' },
      { v: 25, en: 'There is a way which seems right to a man, but in the end it leads to death.', pt: 'Há um caminho que ao homem parece direito, mas o fim dele conduz à morte.' },
      { v: 26, en: 'The appetite of the laboring man labors for him; for his mouth urges him on.', pt: 'O apetite do trabalhador trabalha por ele, porque a sua fome o incita a isso.' },
      { v: 27, en: 'A worthless man devises mischief. His speech is like a scorching fire.', pt: 'O homem vil suscita o mal; e nos seus lábios há como que um fogo ardente.' },
      { v: 28, en: 'A perverse man stirs up strife. A whisperer separates close friends.', pt: 'O homem perverso espalha contendas; e o difamador separa amigos íntimos.' },
      { v: 29, en: 'A man of violence entices his neighbor, and leads him in a way that is not good.', pt: 'O homem violento alicia o seu vizinho, e guia-o por um caminho que não é bom.' },
      { v: 30, en: 'One who winks his eyes to plot perversities, one who compresses his lips, is bent on evil.', pt: 'Quando fecha os olhos fá-lo para maquinar perversidades; quando morde os lábios, efetua o mal.' },
      { v: 31, en: 'Gray hair is a crown of glory. It is attained by a life of righteousness.', pt: 'Coroa de honra são as cãs, a qual se obtém no caminho da justiça.' },
      { v: 32, en: 'One who is slow to anger is better than the mighty; one who rules his spirit, than he who takes a city.', pt: 'Melhor é o longânimo do que o valente; e o que domina o seu espírito do que o que toma uma cidade.' },
      { v: 33, en: 'The lot is cast into the lap, but its every decision is from Yahweh.', pt: 'A sorte se lança no regaço; mas do Senhor procede toda a disposição dela.' },
    ],
    17: [
      { v: 1, en: 'Better is a dry morsel with quietness, than a house full of feasting with strife.', pt: 'Melhor é um bocado seco, e com ele a tranqüilidade, do que a casa cheia de festins, com rixas.' },
      { v: 2, en: 'A servant who deals wisely will rule over a son who causes shame, and shall have a part in the inheritance among the brothers.', pt: 'O servo prudente dominará sobre o filho que procede indignamente; e entre os irmãos receberá da herança.' },
      { v: 3, en: 'The refining pot is for silver, and the furnace for gold, but Yahweh tests the hearts.', pt: 'O crisol é para a prata, e o forno para o ouro; mas o Senhor é que prova os corações.' },
      { v: 4, en: 'An evildoer heeds wicked lips. A liar gives ear to a mischievous tongue.', pt: 'O malfazejo atenta para o lábio iníquo; o mentiroso inclina os ouvidos para a língua maligna.' },
      { v: 5, en: 'Whoever mocks the poor reproaches his Maker. He who is glad at calamity shall not be unpunished.', pt: 'O que escarnece do pobre insulta ao seu Criador; o que se alegra da calamidade não ficará impune.' },
      { v: 6, en: 'Children’s children are the crown of old men; the glory of children are their parents.', pt: 'Coroa dos velhos são os filhos dos filhos; e a glória dos filhos são seus pais.' },
      { v: 7, en: 'Arrogant speech isn’t fitting for a fool, much less do lying lips fit a prince.', pt: 'Não convém ao tolo a fala excelente; quanto menos ao príncipe o lábio mentiroso!' },
      { v: 8, en: 'A bribe is a precious stone in the eyes of him who gives it; wherever he turns, he prospers.', pt: 'Pedra preciosa é a peita aos olhos de quem a oferece; para onde quer que ele se volte, serve-lhe de proveito.' },
      { v: 9, en: 'He who covers an offense promotes love; but he who repeats a matter separates best friends.', pt: 'O que perdoa a transgressão busca a amizade; mas o que renova a questão, afastam amigos íntimos.' },
      { v: 10, en: 'A rebuke enters deeper into one who has understanding than a hundred lashes into a fool.', pt: 'Mais profundamente entra a repreensão no prudente, do que cem açoites no insensato.' },
      { v: 11, en: 'An evil man seeks only rebellion; therefore a cruel messenger shall be sent against him.', pt: 'O rebelde não busca senão o mal; portanto um mensageiro cruel será enviado contra ele.' },
      { v: 12, en: 'Let a bear robbed of her cubs meet a man, rather than a fool in his folly.', pt: 'Encontre-se o homem com a ursa roubada dos filhotes, mas não com o insensato na sua estultícia.' },
      { v: 13, en: 'Whoever rewards evil for good, evil shall not depart from his house.', pt: 'Quanto àquele que torna mal por bem, não se apartará o mal da sua casa.' },
      { v: 14, en: 'The beginning of strife is like breaching a dam, therefore stop contention before quarreling breaks out.', pt: 'O princípio da contenda é como o soltar de águas represadas; deixa por isso a porfia, antes que haja rixas.' },
      { v: 15, en: 'He who justifies the wicked, and he who condemns the righteous, both of them alike are an abomination to Yahweh.', pt: 'O que justifica o ímpio, e o que condena o justo, são abomináveis ao Senhor, tanto um como o outro.' },
      { v: 16, en: 'Why is there money in the hand of a fool to buy wisdom, since he has no understanding?', pt: 'De que serve o preço na mão do tolo para comprar a sabedoria, visto que ele não tem entendimento?' },
      { v: 17, en: 'A friend loves at all times; and a brother is born for adversity.', pt: 'O amigo ama em todo o tempo; e para a angústia nasce o irmão.' },
      { v: 18, en: 'A man void of understanding strikes hands, and becomes collateral in the presence of his neighbor.', pt: 'O homem falto de entendimento compromete-se, tornando-se fiador na presença do seu vizinho.' },
      { v: 19, en: 'He who loves disobedience loves strife. One who builds a high gate seeks destruction.', pt: 'O que ama a contenda ama a transgressao; o que faz alta a sua porta busca a ruína.' },
      { v: 20, en: 'One who has a perverse heart doesn’t find prosperity, and one who has a deceitful tongue falls into trouble.', pt: 'O perverso de coração nunca achará o bem; e o que tem a língua dobre virá a cair no mal.' },
      { v: 21, en: 'He who becomes the father of a fool grieves. The father of a fool has no joy.', pt: 'O que gera um tolo, para sua tristeza o faz; e o pai do insensato não se alegrará.' },
      { v: 22, en: 'A cheerful heart makes good medicine, but a crushed spirit dries up the bones.', pt: 'O coração alegre serve de bom remédio; mas o espírito abatido seca os ossos.' },
      { v: 23, en: 'A wicked man receives a bribe in secret, to pervert the ways of justice.', pt: 'O ímpio recebe do regaço a peita, para perverter as veredas da justiça.' },
      { v: 24, en: 'Wisdom is before the face of one who has understanding, but the eyes of a fool wander to the ends of the earth.', pt: 'O alvo do inteligente é a sabedoria; mas os olhos do insensato estão nas extremidades da terra.' },
      { v: 25, en: 'A foolish son brings grief to his father, and bitterness to her who bore him.', pt: 'O filho insensato é tristeza para seu, pai, e amargura para quem o deu à luz.' },
      { v: 26, en: 'Also to punish the righteous is not good, nor to flog officials for their integrity.', pt: 'Não é bom punir ao justo, nem ferir aos nobres por causa da sua retidão.' },
      { v: 27, en: 'He who spares his words has knowledge. He who is even tempered is a man of understanding.', pt: 'Refreia as suas palavras aquele que possui o conhecimento; e o homem de entendimento é de espírito sereno.' },
      { v: 28, en: 'Even a fool, when he keeps silent, is counted wise. When he shuts his lips, he is thought to be discerning.', pt: 'Até o tolo, estando calado, é tido por sábio; e o que cerra os seus lábios, por entendido.' },
    ],
    18: [
      { v: 1, en: 'An unfriendly man pursues selfishness, and defies all sound judgment.', pt: 'Aquele que vive isolado busca seu próprio desejo; insurge-se contra a verdadeira sabedoria.' },
      { v: 2, en: 'A fool has no delight in understanding, but only in revealing his own opinion.', pt: 'O tolo não toma prazer no entendimento, mas tão somente em revelar a sua opinião.' },
      { v: 3, en: 'When wickedness comes, contempt also comes, and with shame comes disgrace.', pt: 'Quando vem o ímpio, vem também o desprezo; e com a desonra vem o opróbrio.' },
      { v: 4, en: 'The words of a man’s mouth are like deep waters. The fountain of wisdom is like a flowing brook.', pt: 'Aguas profundas são as palavras da boca do homem; e a fonte da sabedoria é um ribeiro que corre.' },
      { v: 5, en: 'To be partial to the faces of the wicked is not good, nor to deprive the innocent of justice.', pt: 'Não é bom ter respeito à pessoa do impio, nem privar o justo do seu direito.' },
      { v: 6, en: 'A fool’s lips come into strife, and his mouth invites beatings.', pt: 'Os lábios do tolo entram em contendas, e a sua boca clama por açoites.' },
      { v: 7, en: 'A fool’s mouth is his destruction, and his lips are a snare to his soul.', pt: 'A boca do tolo é a sua própria destruição, e os seus lábios um laço para a sua alma.' },
      { v: 8, en: 'The words of a gossip are like dainty morsels: they go down into a person’s innermost parts.', pt: 'As palavras do difamador são como bocados doces, que penetram até o íntimo das entranhas.' },
      { v: 9, en: 'One who is slack in his work is brother to him who is a master of destruction.', pt: 'Aquele que é remisso na sua obra é irmão do que é destruidor.' },
      { v: 10, en: 'Yahweh’s name is a strong tower: the righteous run to him, and are safe.', pt: 'Torre forte é o nome do Senhor; para ela corre o justo, e está seguro.' },
      { v: 11, en: 'The rich man’s wealth is his strong city, like an unscalable wall in his own imagination.', pt: 'Os bens do rico são a sua cidade forte, e como um muro alto na sua imaginação.' },
      { v: 12, en: 'Before destruction the heart of man is proud, but before honor is humility.', pt: 'Antes da ruína eleva-se o coração do homem; e adiante da honra vai a humildade.' },
      { v: 13, en: 'He who gives answer before he hears, that is folly and shame to him.', pt: 'Responder antes de ouvir, é estultícia e vergonha.' },
      { v: 14, en: 'A man’s spirit will sustain him in sickness, but a crushed spirit, who can bear?', pt: 'O espírito do homem o sustentará na sua enfermidade; mas ao espírito abatido quem o levantará?' },
      { v: 15, en: 'The heart of the discerning gets knowledge. The ear of the wise seeks knowledge.', pt: 'O coração do entendido adquire conhecimento; e o ouvido dos sábios busca conhecimento;' },
      { v: 16, en: 'A man’s gift makes room for him, and brings him before great men.', pt: 'O presente do homem alarga-lhe o caminho, e leva-o à presença dos grandes.' },
      { v: 17, en: 'He who pleads his cause first seems right; until another comes and questions him.', pt: 'O que primeiro começa o seu pleito parece justo; até que vem o outro e o examina.' },
      { v: 18, en: 'The lot settles disputes, and keeps strong ones apart.', pt: 'A sorte faz cessar os pleitos, e decide entre os poderosos.' },
      { v: 19, en: 'A brother offended is more difficult than a fortified city; and disputes are like the bars of a fortress.', pt: 'um irmão ajudado pelo irmão é como uma cidade fortificada; é forte como os ferrolhos dum castelo.' },
      { v: 20, en: 'A man’s stomach is filled with the fruit of his mouth. With the harvest of his lips he is satisfied.', pt: 'O homem se fartará do fruto da sua boca; dos renovos dos seus lábios se fartará.' },
      { v: 21, en: 'Death and life are in the power of the tongue; those who love it will eat its fruit.', pt: 'A morte e a vida estão no poder da língua; e aquele que a ama comerá do seu fruto.' },
      { v: 22, en: 'Whoever finds a wife finds a good thing, and obtains favor of Yahweh.', pt: 'Quem encontra uma esposa acha uma coisa boa; e alcança o favor do Senhor.' },
      { v: 23, en: 'The poor plead for mercy, but the rich answer harshly.', pt: 'O pobre fala com rogos; mas o rico responde com durezas.' },
      { v: 24, en: 'A man of many companions may be ruined, but there is a friend who sticks closer than a brother.', pt: 'O homem que tem muitos amigos, tem-nos para a sua ruína; mas há um amigo que é mais chegado do que um irmão.' },
    ],
    19: [
      { v: 1, en: 'Better is the poor who walks in his integrity than he who is perverse in his lips and is a fool.', pt: 'Melhor é o pobre que anda na sua integridade, do que aquele que é perverso de lábios e tolo.' },
      { v: 2, en: 'It isn’t good to have zeal without knowledge; nor being hasty with one’s feet and missing the way.', pt: 'Não é bom agir sem refletir; e o que se apressa com seus pés erra o caminho.' },
      { v: 3, en: 'The foolishness of man subverts his way; his heart rages against Yahweh.', pt: 'A estultícia do homem perverte o seu caminho, e o seu coração se irrita contra o Senhor.' },
      { v: 4, en: 'Wealth adds many friends, but the poor is separated from his friend.', pt: 'As riquezas granjeiam muitos amigos; mas do pobre o seu próprio amigo se separa.' },
      { v: 5, en: 'A false witness shall not be unpunished. He who pours out lies shall not go free.', pt: 'A testemunha falsa não ficará impune; e o que profere mentiras não escapará.' },
      { v: 6, en: 'Many will entreat the favor of a ruler, and everyone is a friend to a man who gives gifts.', pt: 'Muitos procurarão o favor do liberal; e cada um é amigo daquele que dá presentes.' },
      { v: 7, en: 'All the relatives of the poor shun him: how much more do his friends avoid him! He pursues them with pleas, but they are gone.', pt: 'Todos os irmãos do pobre o aborrecem; quanto mais se afastam dele os seus amigos! persegue-os com súplicas, mas eles já se foram.' },
      { v: 8, en: 'He who gets wisdom loves his own soul. He who keeps understanding shall find good.', pt: 'O que adquire a sabedoria é amigo de si mesmo; o que guarda o entendimento prosperará.' },
      { v: 9, en: 'A false witness shall not be unpunished. He who utters lies shall perish.', pt: 'A testemunha falsa não ficará impune, e o que profere mentiras perecerá.' },
      { v: 10, en: 'Delicate living is not appropriate for a fool, much less for a servant to have rule over princes.', pt: 'Ao tolo não convém o luxo; quanto menos ao servo dominar os príncipes!' },
      { v: 11, en: 'The discretion of a man makes him slow to anger. It is his glory to overlook an offense.', pt: 'A discrição do homem fá-lo tardio em irar-se; e sua glória está em esquecer ofensas.' },
      { v: 12, en: 'The king’s wrath is like the roaring of a lion, but his favor is like dew on the grass.', pt: 'A ira do rei é como o bramido o leão; mas o seu favor é como o orvalho sobre a erva.' },
      { v: 13, en: 'A foolish son is the calamity of his father. A wife’s quarrels are a continual dripping.', pt: 'O filho insensato é a calamidade do pai; e as rixas da mulher são uma goteira contínua.' },
      { v: 14, en: 'House and riches are an inheritance from fathers, but a prudent wife is from Yahweh.', pt: 'Casa e riquezas são herdadas dos pais; mas a mulher prudente vem do Senhor.' },
      { v: 15, en: 'Slothfulness casts into a deep sleep. The idle soul shall suffer hunger.', pt: 'A preguiça faz cair em profundo sono; e o ocioso padecerá fome.' },
      { v: 16, en: 'He who keeps the commandment keeps his soul, but he who is contemptuous in his ways shall die.', pt: 'Quem guarda o mandamento guarda a sua alma; mas aquele que não faz caso dos seus caminhos morrerá.' },
      { v: 17, en: 'He who has pity on the poor lends to Yahweh; he will reward him.', pt: 'O que se compadece do pobre empresta ao Senhor, que lhe retribuirá o seu benefício.' },
      { v: 18, en: 'Discipline your son, for there is hope; don’t be a willing party to his death.', pt: 'Corrige a teu filho enquanto há esperança; mas não te incites a destruí-lo.' },
      { v: 19, en: 'A hot-tempered man must pay the penalty, for if you rescue him, you must do it again.', pt: 'Homem de grande ira tem de sofrer o castigo; porque se o livrares, terás de o fazer de novo.' },
      { v: 20, en: 'Listen to counsel and receive instruction, that you may be wise in your latter end.', pt: 'Ouve o conselho, e recebe a correção, para que sejas sábio nos teus últimos dias.' },
      { v: 21, en: 'There are many plans in a man’s heart, but Yahweh’s counsel will prevail.', pt: 'Muitos são os planos no coração do homem; mas o desígnio do Senhor, esse prevalecerá.' },
      { v: 22, en: 'That which makes a man to be desired is his kindness. A poor man is better than a liar.', pt: 'O que faz um homem desejável é a sua benignidade; e o pobre é melhor do que o mentiroso.' },
      { v: 23, en: 'The fear of Yahweh leads to life, then contentment; he rests and will not be touched by trouble.', pt: 'O temor do Senhor encaminha para a vida; aquele que o tem ficará satisfeito, e mal nenhum o visitará.' },
      { v: 24, en: 'The sluggard buries his hand in the dish; he will not so much as bring it to his mouth again.', pt: 'O preguiçoso esconde a sua mão no prato, e nem ao menos quer levá-la de novo à boca.' },
      { v: 25, en: 'Flog a scoffer, and the simple will learn prudence; rebuke one who has understanding, and he will gain knowledge.', pt: 'Fere ao escarnecedor, e o simples aprenderá a prudência; repreende ao que tem entendimento, e ele crescerá na ciencia.' },
      { v: 26, en: 'He who robs his father and drives away his mother, is a son who causes shame and brings reproach.', pt: 'O que aflige a seu pai, e faz fugir a sua mãe, é filho que envergonha e desonra.' },
      { v: 27, en: 'If you stop listening to instruction, my son, you will stray from the words of knowledge.', pt: 'Cessa, filho meu, de ouvir a instrução, e logo te desviarás das palavras do conhecimento.' },
      { v: 28, en: 'A corrupt witness mocks justice, and the mouth of the wicked gulps down iniquity.', pt: 'A testemunha vil escarnece da justiça; e a boca dos ímpios engole a iniqüidade.' },
      { v: 29, en: 'Penalties are prepared for scoffers, and beatings for the backs of fools.', pt: 'A condenação está preparada para os escarnecedores, e os açoites para as costas dos tolos.' },
    ],
    20: [
      { v: 1, en: 'Wine is a mocker, and beer is a brawler. Whoever is led astray by them is not wise.', pt: 'O vinho é escarnecedor, e a bebida forte alvoroçadora; e todo aquele que neles errar não e sábio.' },
      { v: 2, en: 'The terror of a king is like the roaring of a lion. He who provokes him to anger forfeits his own life.', pt: 'Como o bramido do leão é o terror do rei; quem o provoca a ira peca contra a sua própria vida.' },
      { v: 3, en: 'It is an honor for a man to keep aloof from strife; but every fool will be quarreling.', pt: 'Honroso é para o homem o desviar-se de questões; mas todo insensato se entremete nelas.' },
      { v: 4, en: 'The sluggard will not plow by reason of the winter; therefore he shall beg in harvest, and have nothing.', pt: 'O preguiçoso não lavra no outono; pelo que mendigará na sega, e nada receberá.' },
      { v: 5, en: 'Counsel in the heart of man is like deep water; but a man of understanding will draw it out.', pt: 'Como águas profundas é o propósito no coração do homem; mas o homem inteligente o descobrirá.' },
      { v: 6, en: 'Many men claim to be men of unfailing love, but who can find a faithful man?', pt: 'Muitos há que proclamam a sua própria bondade; mas o homem fiel, quem o achará?' },
      { v: 7, en: 'A righteous man walks in integrity. Blessed are his children after him.', pt: 'O justo anda na sua integridade; bem-aventurados serão os seus filhos depois dele.' },
      { v: 8, en: 'A king who sits on the throne of judgment scatters away all evil with his eyes.', pt: 'Assentando-se o rei no trono do juízo, com os seus olhos joeira a todo malfeitor.' },
      { v: 9, en: 'Who can say, “I have made my heart pure. I am clean and without sin?”', pt: 'Quem pode dizer: Purifiquei o meu coração, limpo estou de meu pecado?' },
      { v: 10, en: 'Differing weights and differing measures, both of them alike are an abomination to Yahweh.', pt: 'O peso fraudulento e a medida falsa são abominação ao Senhor, tanto uma como outra coisa.' },
      { v: 11, en: 'Even a child makes himself known by his doings, whether his work is pure, and whether it is right.', pt: 'Até a criança se dá a conhecer pelas suas ações, se a sua conduta é pura e reta.' },
      { v: 12, en: 'The hearing ear, and the seeing eye, Yahweh has made even both of them.', pt: 'O ouvido que ouve, e o olho que vê, o Senhor os fez a ambos.' },
      { v: 13, en: 'Don’t love sleep, lest you come to poverty. Open your eyes, and you shall be satisfied with bread.', pt: 'Não ames o sono, para que não empobreças; abre os teus olhos, e te fartarás de pão.' },
      { v: 14, en: '“It’s no good, it’s no good,” says the buyer; but when he is gone his way, then he boasts.', pt: 'Nada vale, nada vale, diz o comprador; mas, depois de retirar-se, então se gaba.' },
      { v: 15, en: 'There is gold and abundance of rubies; but the lips of knowledge are a rare jewel.', pt: 'Há ouro e abundância de pedras preciosas; mas os lábios do conhecimento são jóia de grande valor.' },
      { v: 16, en: 'Take the garment of one who puts up collateral for a stranger; and hold him in pledge for a wayward woman.', pt: 'Tira a roupa àquele que fica por fiador do estranho; e toma penhor daquele que se obriga por estrangeiros.' },
      { v: 17, en: 'Fraudulent food is sweet to a man, but afterwards his mouth is filled with gravel.', pt: 'Suave é ao homem o pão da mentira; mas depois a sua boca se enche de pedrinhas.' },
      { v: 18, en: 'Plans are established by advice; by wise guidance you wage war!', pt: 'Os projetos se confirmam pelos conselhos; assim, pois, com prudencia faze a guerra.' },
      { v: 19, en: 'He who goes about as a tale-bearer reveals secrets; therefore don’t keep company with him who opens wide his lips.', pt: 'O que anda mexericando revela segredos; pelo que não te metas com quem muito abre os seus lábios.' },
      { v: 20, en: 'Whoever curses his father or his mother, his lamp shall be put out in blackness of darkness.', pt: 'O que amaldiçoa a seu pai ou a sua mãe, apagar-se-lhe-á a sua lâmpada nas, mais densas trevas.' },
      { v: 21, en: 'An inheritance quickly gained at the beginning, won’t be blessed in the end.', pt: 'A herança que no princípio é adquirida às pressas, não será abençoada no seu fim.' },
      { v: 22, en: 'Don’t say, “I will pay back evil.” Wait for Yahweh, and he will save you.', pt: 'Não digas: vingar-me-ei do mal; espera pelo Senhor e ele te livrará.' },
      { v: 23, en: 'Yahweh detests differing weights, and dishonest scales are not pleasing.', pt: 'Pesos fraudulentos são abomináveis ao Senhor; e balanças enganosas não são boas.' },
      { v: 24, en: 'A man’s steps are from Yahweh; how then can man understand his way?', pt: 'Os passos do homem são dirigidos pelo Senhor; como, pois, poderá o homem entender o seu caminho?' },
      { v: 25, en: 'It is a snare to a man to make a rash dedication, then later to consider his vows.', pt: 'Laço é para o homem dizer precipitadamente: É santo; e, feitos os votos, então refletir.' },
      { v: 26, en: 'A wise king winnows out the wicked, and drives the threshing wheel over them.', pt: 'O rei sábio joeira os ímpios e faz girar sobre eles a roda.' },
      { v: 27, en: 'The spirit of man is Yahweh’s lamp, searching all his innermost parts.', pt: 'O espírito do homem é a lâmpada do Senhor, a qual esquadrinha todo o mais íntimo do coração.' },
      { v: 28, en: 'Love and faithfulness keep the king safe. His throne is sustained by love.', pt: 'A benignidade e a verdade guardam o rei; e com a benignidade sustém ele o seu trono.' },
      { v: 29, en: 'The glory of young men is their strength. The splendor of old men is their gray hair.', pt: 'A glória dos jovens é a sua força; e a beleza dos velhos são as cãs.' },
      { v: 30, en: 'Wounding blows cleanse away evil, and beatings purge the innermost parts.', pt: 'Os açoites que ferem purificam do mal; e as feridas penetram até o mais íntimo do corpo.' },
    ],
    21: [
      { v: 1, en: 'The king’s heart is in Yahweh’s hand like the watercourses. He turns it wherever he desires.', pt: 'Como corrente de águas é o coração do rei na mão do Senhor; ele o inclina para onde quer.' },
      { v: 2, en: 'Every way of a man is right in his own eyes, but Yahweh weighs the hearts.', pt: 'Todo caminho do homem é reto aos seus olhos; mas o Senhor pesa os corações.' },
      { v: 3, en: 'To do righteousness and justice is more acceptable to Yahweh than sacrifice.', pt: 'Fazer justiça e julgar com retidão é mais aceitável ao Senhor do que oferecer-lhe sacrifício.' },
      { v: 4, en: 'A high look, and a proud heart, the lamp of the wicked, is sin.', pt: 'Olhar altivo e coração orgulhoso, tal lâmpada dos ímpios é pecado.' },
      { v: 5, en: 'The plans of the diligent surely lead to profit; and everyone who is hasty surely rushes to poverty.', pt: 'Os planos do diligente conduzem à abundância; mas todo precipitado apressa-se para a penúria.' },
      { v: 6, en: 'Getting treasures by a lying tongue is a fleeting vapor for those who seek death.', pt: 'Ajuntar tesouros com língua falsa é uma vaidade fugitiva; aqueles que os buscam, buscam a morte.' },
      { v: 7, en: 'The violence of the wicked will drive them away, because they refuse to do what is right.', pt: 'A violência dos ímpios arrebatá-los-á, porquanto recusam praticar a justiça.' },
      { v: 8, en: 'The way of the guilty is devious, but the conduct of the innocent is upright.', pt: 'O caminho do homem perverso é tortuoso; mas o proceder do puro é reto.' },
      { v: 9, en: 'It is better to dwell in the corner of the housetop, than to share a house with a contentious woman.', pt: 'Melhor é morar num canto do eirado, do que com a mulher rixosa numa casa ampla.' },
      { v: 10, en: 'The soul of the wicked desires evil; his neighbor finds no mercy in his eyes.', pt: 'A alma do ímpio deseja o mal; o seu próximo não agrada aos seus olhos.' },
      { v: 11, en: 'When the mocker is punished, the simple gains wisdom. When the wise is instructed, he receives knowledge.', pt: 'Quando o escarnecedor é castigado, o simples torna-se sábio; e, quando o sábio é instruído, recebe o conhecimento.' },
      { v: 12, en: 'The Righteous One considers the house of the wicked, and brings the wicked to ruin.', pt: 'O justo observa a casa do ímpio; precipitam-se os ímpios na ruína.' },
      { v: 13, en: 'Whoever stops his ears at the cry of the poor, he will also cry out, but shall not be heard.', pt: 'Quem tapa o seu ouvido ao clamor do pobre, também clamará e não será ouvido.' },
      { v: 14, en: 'A gift in secret pacifies anger; and a bribe in the cloak, strong wrath.', pt: 'O presente que se dá em segredo aplaca a ira; e a dádiva às escondidas, a forte indignação.' },
      { v: 15, en: 'It is joy to the righteous to do justice; but it is a destruction to the workers of iniquity.', pt: 'A execução da justiça é motivo de alegria para o justo; mas é espanto para os que praticam a iniqüidade.' },
      { v: 16, en: 'The man who wanders out of the way of understanding shall rest in the assembly of the departed spirits.', pt: 'O homem que anda desviado do caminho do entendimento repousará na congregação dos mortos.' },
      { v: 17, en: 'He who loves pleasure shall be a poor man. He who loves wine and oil shall not be rich.', pt: 'Quem ama os prazeres empobrecerá; quem ama o vinho e o azeite nunca enriquecera.' },
      { v: 18, en: 'The wicked is a ransom for the righteous; the treacherous for the upright.', pt: 'Resgate para o justo é o ímpio; e em lugar do reto ficará o prevaricador.' },
      { v: 19, en: 'It is better to dwell in a desert land, than with a contentious and fretful woman.', pt: 'Melhor é morar numa terra deserta do que com a mulher rixosa e iracunda.' },
      { v: 20, en: 'There is precious treasure and oil in the dwelling of the wise; but a foolish man swallows it up.', pt: 'Há tesouro precioso e azeite na casa do sábio; mas o homem insensato os devora.' },
      { v: 21, en: 'He who follows after righteousness and kindness finds life, righteousness, and honor.', pt: 'Aquele que segue a justiça e a bondade achará a vida, a justiça e a honra.' },
      { v: 22, en: 'A wise man scales the city of the mighty, and brings down the strength of its confidence.', pt: 'O sábio escala a cidade dos valentes, e derriba a fortaleza em que ela confia.' },
      { v: 23, en: 'Whoever guards his mouth and his tongue keeps his soul from troubles.', pt: 'O que guarda a sua boca e a sua língua, guarda das angústias a sua alma.' },
      { v: 24, en: 'The proud and haughty man, “scoffer” is his name; he works in the arrogance of pride.', pt: 'Quanto ao soberbo e presumido, zombador é seu nome; ele procede com insolente orgulho.' },
      { v: 25, en: 'The desire of the sluggard kills him, for his hands refuse to labor.', pt: 'O desejo do preguiçoso o mata; porque as suas mãos recusam-se a trabalhar.' },
      { v: 26, en: 'There are those who covet greedily all day long; but the righteous give and don’t withhold.', pt: 'Todo o dia o ímpio cobiça; mas o justo dá, e não retém.' },
      { v: 27, en: 'The sacrifice of the wicked is an abomination; how much more, when he brings it with a wicked mind!', pt: 'O sacrifício dos ímpios é abominaçao; quanto mais oferecendo-o com intenção maligna!' },
      { v: 28, en: 'A false witness will perish, and a man who listens speaks to eternity.', pt: 'A testemunha mentirosa perecerá; mas o homem que ouve falará sem ser contestado.' },
      { v: 29, en: 'A wicked man hardens his face; but as for the upright, he establishes his ways.', pt: 'O homem ímpio endurece o seu rosto; mas o reto considera os seus caminhos.' },
      { v: 30, en: 'There is no wisdom nor understanding nor counsel against Yahweh.', pt: 'Não há sabedoria, nem entendimento, nem conselho contra o Senhor.' },
      { v: 31, en: 'The horse is prepared for the day of battle; but victory is with Yahweh.', pt: 'O cavalo prepara-se para o dia da batalha; mas do Senhor vem a vitória.' },
    ],
    22: [
      { v: 1, en: 'A good name is more desirable than great riches, and loving favor is better than silver and gold.', pt: 'Mais digno de ser escolhido é o bom nome do que as muitas riquezas; e o favor é melhor do que a prata e o ouro.' },
      { v: 2, en: 'The rich and the poor have this in common: Yahweh is the maker of them all.', pt: 'O rico e o pobre se encontram; quem os faz a ambos é o Senhor.' },
      { v: 3, en: 'A prudent man sees danger, and hides himself; but the simple pass on, and suffer for it.', pt: 'O prudente vê o perigo e esconde-se; mas os simples passam adiante e sofrem a pena.' },
      { v: 4, en: 'The result of humility and the fear of Yahweh is wealth, honor, and life.', pt: 'O galardão da humildade e do temor do Senhor é riquezas, e honra e vida.' },
      { v: 5, en: 'Thorns and snares are in the path of the wicked: whoever guards his soul stays from them.', pt: 'Espinhos e laços há no caminho do perverso; o que guarda a sua alma retira-se para longe deles.' },
      { v: 6, en: 'Train up a child in the way he should go, and when he is old he will not depart from it.', pt: 'Instrui o menino no caminho em que deve andar, e até quando envelhecer não se desviará dele.' },
      { v: 7, en: 'The rich rule over the poor. The borrower is servant to the lender.', pt: 'O rico domina sobre os pobres; e o que toma emprestado é servo do que empresta.' },
      { v: 8, en: 'He who sows wickedness reaps trouble, and the rod of his fury will be destroyed.', pt: 'O que semear a perversidade segará males; e a vara da sua indignação falhará.' },
      { v: 9, en: 'He who has a generous eye will be blessed; for he shares his food with the poor.', pt: 'Quem vê com olhos bondosos será abençoado; porque dá do seu pão ao pobre.' },
      { v: 10, en: 'Drive out the mocker, and strife will go out; yes, quarrels and insults will stop.', pt: 'Lança fora ao escarnecedor, e a contenda se irá; cessarao a rixa e a injúria.' },
      { v: 11, en: 'He who loves purity of heart and speaks gracefully is the king’s friend.', pt: 'O que ama a pureza do coração, e que tem graça nos seus lábios, terá por seu amigo o rei.' },
      { v: 12, en: 'Yahweh’s eyes watch over knowledge; but he frustrates the words of the unfaithful.', pt: 'Os olhos do Senhor preservam o que tem conhecimento; mas ele transtorna as palavras do prevaricador.' },
      { v: 13, en: 'The sluggard says, “There is a lion outside! I will be killed in the streets!”', pt: 'Diz o preguiçoso: um leão está lá fora; serei morto no meio das ruas.' },
      { v: 14, en: 'The mouth of an adulteress is a deep pit. He who is under Yahweh’s wrath will fall into it.', pt: 'Cova profunda é a boca da adúltera; aquele contra quem o Senhor está irado cairá nela.' },
      { v: 15, en: 'Folly is bound up in the heart of a child: the rod of discipline drives it far from him.', pt: 'A estultícia está ligada ao coração do menino; mas a vara da correção a afugentará dele.' },
      { v: 16, en: 'Whoever oppresses the poor for his own increase and whoever gives to the rich, both come to poverty.', pt: 'O que para aumentar o seu lucro oprime o pobre, e dá ao rico, certamente chegará à: penuria.' },
      { v: 17, en: 'Turn your ear, and listen to the words of the wise. Apply your heart to my teaching.', pt: 'Inclina o teu ouvido e ouve as palavras dos sábios, e aplica o teu coração ao meu conhecimento.' },
      { v: 18, en: 'For it is a pleasant thing if you keep them within you, if all of them are ready on your lips.', pt: 'Porque será coisa suave, se os guardares no teu peito, se estiverem todos eles prontos nos teus lábios.' },
      { v: 19, en: 'I teach you today, even you, So that your trust may be in Yahweh.', pt: 'Para que a tua confiança esteja no senhor, a ti tos fiz saber hoje, sim, a ti mesmo.' },
      { v: 20, en: 'Haven’t I written to you thirty excellent things of counsel and knowledge,', pt: 'Porventura não te escrevi excelentes coisas acerca dos conselhos e do conhecimento,' },
      { v: 21, en: 'To teach you truth, reliable words, to give sound answers to the ones who sent you?', pt: 'para te fazer saber a certeza das palavras de verdade, para que possas responder com palavras de verdade aos que te enviarem?' },
      { v: 22, en: 'Don’t exploit the poor, because he is poor; and don’t crush the needy in court;', pt: 'Não roubes ao pobre, porque é pobre; nem oprimas ao aflito na porta;' },
      { v: 23, en: 'for Yahweh will plead their case, and plunder the life of those who plunder them.', pt: 'porque o Senhor defenderá a sua causa em juízo, e aos que os roubam lhes tirará a vida.' },
      { v: 24, en: 'Don’t befriend a hot-tempered man, and don’t associate with one who harbors anger:', pt: 'Não faças amizade com o iracundo; nem andes com o homem colérico;' },
      { v: 25, en: 'lest you learn his ways, and ensnare your soul.', pt: 'para que não aprendas as suas veredas, e tomes um laço para a tua alma.' },
      { v: 26, en: 'Don’t you be one of those who strike hands, of those who are collateral for debts.', pt: 'Não estejas entre os que se comprometem, que ficam por fiadores de dívidas.' },
      { v: 27, en: 'If you don’t have means to pay, why should he take away your bed from under you?', pt: 'Se não tens com que pagar, por que tirariam a tua cama de debaixo de ti?' },
      { v: 28, en: 'Don’t move the ancient boundary stone, which your fathers have set up.', pt: 'Não removas os limites antigos que teus pais fixaram.' },
      { v: 29, en: 'Do you see a man skilled in his work? He will serve kings. He won’t serve obscure men.', pt: 'Vês um homem hábil na sua obrar? esse perante reis assistirá; e não assistirá perante homens obscuros.' },
    ],
    23: [
      { v: 1, en: 'When you sit to eat with a ruler, consider diligently what is before you;', pt: 'Quando te assentares a comer com um governador, atenta bem para aquele que está diante de ti;' },
      { v: 2, en: 'put a knife to your throat, if you are a man given to appetite.', pt: 'e põe uma faca à tua garganta, se fores homem de grande apetite.' },
      { v: 3, en: 'Don’t be desirous of his dainties, since they are deceitful food.', pt: 'Não cobices os seus manjares gostosos, porque é comida enganadora.' },
      { v: 4, en: 'Don’t weary yourself to be rich. In your wisdom, show restraint.', pt: 'Não te fatigues para seres rico; dá de mão à tua própria sabedoria:' },
      { v: 5, en: 'Why do you set your eyes on that which is not? For it certainly sprouts wings like an eagle and flies in the sky.', pt: 'Fitando tu os olhos nas riquezas, elas se vão; pois fazem para si asas, como a águia, voam para o céu.' },
      { v: 6, en: 'Don’t eat the food of him who has a stingy eye, and don’t crave his delicacies:', pt: 'Não comas o pão do avarento, nem cobices os seus manjares gostosos.' },
      { v: 7, en: 'for as he thinks about the cost, so he is. “Eat and drink!” he says to you, but his heart is not with you.', pt: 'Porque, como ele pensa consigo mesmo, assim é; ele te diz: Come e bebe; mas o seu coração não está contigo.' },
      { v: 8, en: 'The morsel which you have eaten you shall vomit up, and lose your good words.', pt: 'Vomitarás o bocado que comeste, e perderás as tuas suaves palavras.' },
      { v: 9, en: 'Don’t speak in the ears of a fool, for he will despise the wisdom of your words.', pt: 'Não fales aos ouvidos do tolo; porque desprezará a sabedoria das tuas palavras.' },
      { v: 10, en: 'Don’t move the ancient boundary stone. Don’t encroach on the fields of the fatherless:', pt: 'Não removas os limites antigos; nem entres nos campos dos órfãos,' },
      { v: 11, en: 'for their Defender is strong. He will plead their case against you.', pt: 'porque o seu redentor é forte; ele lhes pleiteará a causa contra ti.' },
      { v: 12, en: 'Apply your heart to instruction, and your ears to the words of knowledge.', pt: 'Aplica o teu coração à instrução, e os teus ouvidos às palavras do conhecimento.' },
      { v: 13, en: 'Don’t withhold correction from a child. If you punish him with the rod, he will not die.', pt: 'Não retires da criança a disciplina; porque, fustigando-a tu com a vara, nem por isso morrerá.' },
      { v: 14, en: 'Punish him with the rod, and save his soul from Sheol.', pt: 'Tu a fustigarás com a vara e livrarás a sua alma do Seol.' },
      { v: 15, en: 'My son, if your heart is wise, then my heart will be glad, even mine:', pt: 'Filho meu, se o teu coração for sábio, alegrar-se-á o meu coração, sim, ó, meu próprio;' },
      { v: 16, en: 'yes, my heart will rejoice, when your lips speak what is right.', pt: 'e exultará o meu coração, quando os teus lábios falarem coisas retas.' },
      { v: 17, en: 'Don’t let your heart envy sinners; but rather fear Yahweh all day long.', pt: 'Não tenhas inveja dos pecadores; antes conserva-te no temor do Senhor todo o dia.' },
      { v: 18, en: 'Indeed surely there is a future hope, and your hope will not be cut off.', pt: 'Porque deveras terás uma recompensa; não será malograda a tua esperança.' },
      { v: 19, en: 'Listen, my son, and be wise, and keep your heart on the right path!', pt: 'Ouve tu, filho meu, e sê sábio; e dirige no caminho o teu coração.' },
      { v: 20, en: 'Don’t be among ones drinking too much wine, or those who gorge themselves on meat:', pt: 'Não estejas entre os beberrões de vinho, nem entre os comilões de carne.' },
      { v: 21, en: 'for the drunkard and the glutton shall become poor; and drowsiness clothes them in rags.', pt: 'Porque o beberrão e o comilão caem em pobreza; e a sonolência cobrirá de trapos o homem.' },
      { v: 22, en: 'Listen to your father who gave you life, and don’t despise your mother when she is old.', pt: 'Ouve a teu pai, que te gerou; e não desprezes a tua mãe, quando ela envelhecer.' },
      { v: 23, en: 'Buy the truth, and don’t sell it. Get wisdom, discipline, and understanding.', pt: 'Compra a verdade, e não a vendas; sim, a sabedoria, a disciplina, e o entendimento.' },
      { v: 24, en: 'The father of the righteous has great joy. Whoever fathers a wise child delights in him.', pt: 'Grandemente se regozijará o pai do justo; e quem gerar um filho sábio, nele se alegrará.' },
      { v: 25, en: 'Let your father and your mother be glad! Let her who bore you rejoice!', pt: 'Alegrem-se teu pai e tua mãe, e regozije-se aquela que te deu à luz.' },
      { v: 26, en: 'My son, give me your heart; and let your eyes keep in my ways.', pt: 'Filho meu, dá-me o teu coração; e deleitem-se os teus olhos nos meus caminhos.' },
      { v: 27, en: 'For a prostitute is a deep pit; and a wayward wife is a narrow well.', pt: 'Porque cova profunda é a prostituta; e poço estreito é a aventureira.' },
      { v: 28, en: 'Yes, she lies in wait like a robber, and increases the unfaithful among men.', pt: 'Também ela, como o salteador, se põe a espreitar; e multiplica entre os homens os prevaricadores.' },
      { v: 29, en: 'Who has woe? Who has sorrow? Who has strife? Who has complaints? Who has needless bruises? Who has bloodshot eyes?', pt: 'Para quem são os ais? para quem os pesares? para quem as pelejas, para quem as queixas? para quem as feridas sem causa? e para quem os olhos vermelhos?' },
      { v: 30, en: 'Those who stay long at the wine; those who go to seek out mixed wine.', pt: 'Para os que se demoram perto do vinho, para os que andam buscando bebida misturada.' },
      { v: 31, en: 'Don’t look at the wine when it is red, when it sparkles in the cup, when it goes down smoothly.', pt: 'Não olhes para o vinho quando se mostra vermelho, quando resplandece no copo e se escoa suavemente.' },
      { v: 32, en: 'In the end, it bites like a snake, and poisons like a viper.', pt: 'No seu fim morderá como a cobra, e como o basilisco picará.' },
      { v: 33, en: 'Your eyes will see strange things, and your mind will imagine confusing things.', pt: 'Os teus olhos verão coisas estranhas, e tu falarás perversidades.' },
      { v: 34, en: 'Yes, you will be as he who lies down in the middle of the sea, or as he who lies on top of the rigging:', pt: 'o serás como o que se deita no meio do mar, e como o que dorme no topo do mastro.' },
      { v: 35, en: '“They hit me, and I was not hurt! They beat me, and I don’t feel it! When will I wake up? I can do it again. I can find another.”', pt: 'E diràs: Espancaram-me, e não me doeu; bateram-me, e não o senti; quando virei a despertar? ainda tornarei a buscá-lo outra vez.' },
    ],
    24: [
      { v: 1, en: 'Don’t be envious of evil men; neither desire to be with them:', pt: 'Não tenhas inveja dos homens malignos; nem desejes estar com eles;' },
      { v: 2, en: 'for their hearts plot violence, and their lips talk about mischief.', pt: 'porque o seu coração medita a violência; e os seus lábios falam maliciosamente.' },
      { v: 3, en: 'Through wisdom a house is built; by understanding it is established;', pt: 'Com a sabedoria se edifica a casa, e com o entendimento ela se estabelece;' },
      { v: 4, en: 'by knowledge the rooms are filled with all rare and beautiful treasure.', pt: 'e pelo conhecimento se encherão as câmaras de todas as riquezas preciosas e deleitáveis.' },
      { v: 5, en: 'A wise man has great power; and a knowledgeable man increases strength;', pt: 'O sábio é mais poderoso do que o forte; e o inteligente do que o que possui a força.' },
      { v: 6, en: 'for by wise guidance you wage your war; and victory is in many advisors.', pt: 'Porque com conselhos prudentes tu podes fazer a guerra; e há vitória na multidão dos conselheiros.' },
      { v: 7, en: 'Wisdom is too high for a fool: he doesn’t open his mouth in the gate.', pt: 'A sabedoria é alta demais para o insensato; ele não abre a sua boca na porta.' },
      { v: 8, en: 'One who plots to do evil will be called a schemer.', pt: 'Aquele que cuida em fazer o mal, mestre de maus intentos o chamarão.' },
      { v: 9, en: 'The schemes of folly are sin. The mocker is detested by men.', pt: 'O desígnio do insensato é pecado; e abominável aos homens é o escarnecedor.' },
      { v: 10, en: 'If you falter in the time of trouble, your strength is small.', pt: 'Se enfraqueces no dia da angústia, a tua força é pequena.' },
      { v: 11, en: 'Rescue those who are being led away to death! Indeed, hold back those who are staggering to the slaughter!', pt: 'Livra os que estão sendo levados à morte, detém os que vão tropeçando para a matança.' },
      { v: 12, en: 'If you say, “Behold, we didn’t know this”; doesn’t he who weighs the hearts consider it? He who keeps your soul, doesn’t he know it? Shall he not render to every man according to his work?', pt: 'Se disseres: Eis que não o sabemos; porventura aquele que pesa os corações não o percebe? e aquele que guarda a tua vida não o sabe? e não retribuirá a cada um conforme a sua obra?' },
      { v: 13, en: 'My son, eat honey, for it is good; the droppings of the honeycomb, which are sweet to your taste:', pt: 'Come mel, filho meu, porque é bom, e do favo de mel, que é doce ao teu paladar.' },
      { v: 14, en: 'so you shall know wisdom to be to your soul; if you have found it, then there will be a reward, your hope will not be cut off.', pt: 'Sabe que é assim a sabedoria para a tua alma: se a achares, haverá para ti recompensa, e não será malograda a tua esperança.' },
      { v: 15, en: 'Don’t lay in wait, wicked man, against the habitation of the righteous. Don’t destroy his resting place:', pt: 'Não te ponhas de emboscada, ó ímpio, contra a habitação do justo; nem assoles a sua pousada.' },
      { v: 16, en: 'for a righteous man falls seven times, and rises up again; but the wicked are overthrown by calamity.', pt: 'Porque sete vezes cai o justo, e se levanta; mas os ímpios são derribados pela calamidade.' },
      { v: 17, en: 'Don’t rejoice when your enemy falls. Don’t let your heart be glad when he is overthrown;', pt: 'Quando cair o teu inimigo, não te alegres, e quando tropeçar, não se regozije o teu coração;' },
      { v: 18, en: 'lest Yahweh see it, and it displease him, and he turn away his wrath from him.', pt: 'para que o Senhor não o veja, e isso seja mau aos seus olhos, e desvie dele, a sua ira.' },
      { v: 19, en: 'Don’t fret yourself because of evildoers; neither be envious of the wicked:', pt: 'Não te aflijas por causa dos malfeitores; nem tenhas inveja dos ímpios;' },
      { v: 20, en: 'for there will be no reward to the evil man; and the lamp of the wicked shall be snuffed out.', pt: 'porque o maligno não tem futuro; e a lâmpada dos ímpios se apagará.' },
      { v: 21, en: 'My son, fear Yahweh and the king. Don’t join those who are rebellious:', pt: 'Filho meu, teme ao Senhor, e ao rei; e não te entremetas com os que gostam de mudanças.' },
      { v: 22, en: 'for their calamity will rise suddenly; the destruction from them both—who knows?', pt: 'Porque de repente se levantará a sua calamidade; e a ruína deles, quem a conhecerá?' },
      { v: 23, en: 'These also are sayings of the wise. To show partiality in judgment is not good.', pt: 'Também estes são provérbios dos sábios: Fazer acepção de pessoas no juízo não é bom.' },
      { v: 24, en: 'He who says to the wicked, “You are righteous”; peoples will curse him, and nations will abhor him—', pt: 'Aquele que disser ao ímpio: Justo és; os povos o amaldiçoarão, as nações o detestarão;' },
      { v: 25, en: 'but it will go well with those who convict the guilty, and a rich blessing will come on them.', pt: 'mas para os que julgam retamente haverá delícias, e sobre eles virá copiosa bênção.' },
      { v: 26, en: 'An honest answer is like a kiss on the lips.', pt: 'O que responde com palavras retas beija os lábios.' },
      { v: 27, en: 'Prepare your work outside, and get your fields ready. Afterwards, build your house.', pt: 'Prepara os teus trabalhos de fora, apronta bem o teu campo; e depois edifica a tua casa.' },
      { v: 28, en: 'Don’t be a witness against your neighbor without cause. Don’t deceive with your lips.', pt: 'Não sejas testemunha sem causa contra o teu próximo; e não enganes com os teus lábios.' },
      { v: 29, en: 'Don’t say, “I will do to him as he has done to me; I will render to the man according to his work.”', pt: 'Não digas: Como ele me fez a mim, assim lhe farei a ele; pagarei a cada um segundo a sua obra.' },
      { v: 30, en: 'I went by the field of the sluggard, by the vineyard of the man void of understanding;', pt: 'Passei junto ao campo do preguiçoso, e junto à vinha do homem falto de entendimento;' },
      { v: 31, en: 'Behold, it was all grown over with thorns. Its surface was covered with nettles, and its stone wall was broken down.', pt: 'e eis que tudo estava cheio de cardos, e a sua superfície coberta de urtigas, e o seu muro de pedra estava derrubado.' },
      { v: 32, en: 'Then I saw, and considered well. I saw, and received instruction:', pt: 'O que tendo eu visto, o considerei; e, vendo-o, recebi instrução.' },
      { v: 33, en: 'a little sleep, a little slumber, a little folding of the hands to sleep;', pt: 'Um pouco para dormir, um pouco para toscanejar, um pouco para cruzar os braços em repouso;' },
      { v: 34, en: 'so your poverty will come as a robber, and your want as an armed man.', pt: 'assim sobrevirá a tua pobreza como um salteador, e a tua necessidade como um homem armado.' },
    ],
    25: [
      { v: 1, en: 'These also are proverbs of Solomon, which the men of Hezekiah king of Judah copied out.', pt: 'Também estes são provérbios de Salomão, os quais transcreveram os homens de Ezequias, rei de Judá.' },
      { v: 2, en: 'It is the glory of God to conceal a thing, but the glory of kings is to search out a matter.', pt: 'A glória de Deus é encobrir as coisas; mas a glória dos reis é esquadrinhá-las.' },
      { v: 3, en: 'As the heavens for height, and the earth for depth, so the hearts of kings are unsearchable.', pt: 'Como o céu na sua altura, e como a terra na sua profundidade, assim o coração dos reis é inescrutável.' },
      { v: 4, en: 'Take away the dross from the silver, and material comes out for the refiner;', pt: 'Tira da prata a escória, e sairá um vaso para o fundidor.' },
      { v: 5, en: 'Take away the wicked from the king’s presence, and his throne will be established in righteousness.', pt: 'Tira o ímpio da presença do rei, e o seu trono se firmará na justiça.' },
      { v: 6, en: 'Don’t exalt yourself in the presence of the king, or claim a place among great men;', pt: 'Não reclames para ti honra na presença do rei, nem te ponhas no lugar dos grandes;' },
      { v: 7, en: 'for it is better that it be said to you, “Come up here,” than that you should be put lower in the presence of the prince, whom your eyes have seen.', pt: 'porque melhor é que te digam: Sobe, para aqui; do que seres humilhado perante o príncipe.' },
      { v: 8, en: 'Don’t be hasty in bringing charges to court. What will you do in the end when your neighbor shames you?', pt: 'O que os teus olhos viram, não te apresses a revelar, para depois, ao fim, não saberes o que hás de fazer, podendo-te confundir o teu próximo.' },
      { v: 9, en: 'Debate your case with your neighbor, and don’t betray the confidence of another;', pt: 'Pleiteia a tua causa com o teu próximo mesmo; e não reveles o segredo de outrem;' },
      { v: 10, en: 'lest one who hears it put you to shame, and your bad reputation never depart.', pt: 'para que não te desonre aquele que o ouvir, não se apartando de ti a infâmia.' },
      { v: 11, en: 'A word fitly spoken is like apples of gold in settings of silver.', pt: 'Como maçãs de ouro em salvas de prata, assim é a palavra dita a seu tempo.' },
      { v: 12, en: 'As an earring of gold, and an ornament of fine gold, so is a wise reprover to an obedient ear.', pt: 'Como pendentes de ouro e gargantilhas de ouro puro, assim é o sábio repreensor para o ouvido obediente.' },
      { v: 13, en: 'As the cold of snow in the time of harvest, so is a faithful messenger to those who send him; for he refreshes the soul of his masters.', pt: 'Como o frescor de neve no tempo da sega, assim é o mensageiro fiel para com os que o enviam, porque refrigera o espírito dos seus senhores.' },
      { v: 14, en: 'As clouds and wind without rain, so is he who boasts of gifts deceptively.', pt: 'como nuvens e ventos que não trazem chuva, assim é o homem que se gaba de dádivas que não fez.' },
      { v: 15, en: 'By patience a ruler is persuaded. A soft tongue breaks the bone.', pt: 'Pela longanimidade se persuade o príncipe, e a língua branda quebranta os ossos.' },
      { v: 16, en: 'Have you found honey? Eat as much as is sufficient for you, lest you eat too much, and vomit it.', pt: 'Se achaste mel, come somente o que te basta, para que porventura não te fartes dele, e o venhas a vomitar.' },
      { v: 17, en: 'Let your foot be seldom in your neighbor’s house, lest he be weary of you, and hate you.', pt: 'Põe raramente o teu pé na casa do teu próximo, para que não se enfade de ti, e te aborreça.' },
      { v: 18, en: 'A man who gives false testimony against his neighbor is like a club, a sword, or a sharp arrow.', pt: 'Malho, e espada, e flecha aguda é o homem que levanta falso testemunho contra o seu próximo.' },
      { v: 19, en: 'Confidence in someone unfaithful in time of trouble is like a bad tooth, or a lame foot.', pt: 'Como dente quebrado, e pé deslocado, é a confiança no homem desleal, no dia da angústia.' },
      { v: 20, en: 'As one who takes away a garment in cold weather, or vinegar on soda, so is one who sings songs to a heavy heart.', pt: 'O que entoa canções ao coração aflito é como aquele que despe uma peça de roupa num dia de frio, e como vinagre sobre a chaga.' },
      { v: 21, en: 'If your enemy is hungry, give him food to eat. If he is thirsty, give him water to drink:', pt: 'Se o teu inimigo tiver fome, dá-lhe pão para comer, e se tiver sede, dá-lhe água para beber;' },
      { v: 22, en: 'for you will heap coals of fire on his head, and Yahweh will reward you.', pt: 'porque assim lhe amontoarás brasas sobre a cabeça, e o Senhor te recompensará.' },
      { v: 23, en: 'The north wind produces rain; so a backbiting tongue brings an angry face.', pt: 'O vento norte traz chuva, e a língua caluniadora, o rosto irado.' },
      { v: 24, en: 'It is better to dwell in the corner of the housetop, than to share a house with a contentious woman.', pt: 'Melhor é morar num canto do eirado, do que com a mulher rixosa numa casa ampla.' },
      { v: 25, en: 'Like cold water to a thirsty soul, so is good news from a far country.', pt: 'Como água fresca para o homem sedento, tais são as boas-novas de terra remota.' },
      { v: 26, en: 'Like a muddied spring, and a polluted well, so is a righteous man who gives way before the wicked.', pt: 'Como fonte turva, e manancial poluído, assim é o justo que cede lugar diante do ímpio.' },
      { v: 27, en: 'It is not good to eat much honey; nor is it honorable to seek one’s own honor.', pt: 'comer muito mel não é bom; não multipliques, pois, as palavras de lisonja.' },
      { v: 28, en: 'Like a city that is broken down and without walls is a man whose spirit is without restraint.', pt: 'Como a cidade derribada, que não tem muros, assim é o homem que não pode conter o seu espírito.' },
    ],
    26: [
      { v: 1, en: 'Like snow in summer, and as rain in harvest, so honor is not fitting for a fool.', pt: 'Como a neve no verão, e como a chuva no tempo da ceifa, assim não convém ao tolo a honra.' },
      { v: 2, en: 'Like a fluttering sparrow, like a darting swallow, so the undeserved curse doesn’t come to rest.', pt: 'Como o pássaro no seu vaguear, como a andorinha no seu voar, assim a maldição sem causa não encontra pouso.' },
      { v: 3, en: 'A whip is for the horse, a bridle for the donkey, and a rod for the back of fools!', pt: 'O açoite é para o cavalo, o freio para o jumento, e a vara para as costas dos tolos.' },
      { v: 4, en: 'Don’t answer a fool according to his folly, lest you also be like him.', pt: 'Não respondas ao tolo segundo a sua estultícia, para que também não te faças semelhante a ele.' },
      { v: 5, en: 'Answer a fool according to his folly, lest he be wise in his own eyes.', pt: 'Responde ao tolo segundo a sua estultícia, para que ele não seja sábio aos seus próprios olhos.' },
      { v: 6, en: 'One who sends a message by the hand of a fool is cutting off feet and drinking violence.', pt: 'Os pés decepa, e o dano bebe, quem manda mensagens pela mão dum tolo.' },
      { v: 7, en: 'Like the legs of the lame that hang loose, so is a parable in the mouth of fools.', pt: 'As pernas do coxo pendem frouxas; assim é o provérbio na boca dos tolos.' },
      { v: 8, en: 'As one who binds a stone in a sling, so is he who gives honor to a fool.', pt: 'Como o que ata a pedra na funda, assim é aquele que dá honra ao tolo.' },
      { v: 9, en: 'Like a thorn bush that goes into the hand of a drunkard, so is a parable in the mouth of fools.', pt: 'Como o espinho que entra na mão do ébrio, assim é o provérbio na mão dos tolos.' },
      { v: 10, en: 'As an archer who wounds all, so is he who hires a fool or he who hires those who pass by.', pt: 'Como o flecheiro que fere a todos, assim é aquele que assalaria ao transeunte tolo, ou ao ébrio.' },
      { v: 11, en: 'As a dog that returns to his vomit, so is a fool who repeats his folly.', pt: 'Como o cão que torna ao seu vômito, assim é o tolo que reitera a sua estultícia.' },
      { v: 12, en: 'Do you see a man wise in his own eyes? There is more hope for a fool than for him.', pt: 'Vês um homem que é sábio a seus próprios olhos? Maior esperança há para o tolo do que para ele.' },
      { v: 13, en: 'The sluggard says, “There is a lion in the road! A fierce lion roams the streets!”', pt: 'Diz o preguiçoso: Um leão está no caminho; um leão está nas ruas.' },
      { v: 14, en: 'As the door turns on its hinges, so does the sluggard on his bed.', pt: 'Como a porta se revolve nos seus gonzos, assim o faz o preguiçoso na sua cama.' },
      { v: 15, en: 'The sluggard buries his hand in the dish. He is too lazy to bring it back to his mouth.', pt: 'O preguiçoso esconde a sua mão no prato, e nem ao menos quer levá-la de novo à boca.' },
      { v: 16, en: 'The sluggard is wiser in his own eyes than seven men who answer with discretion.', pt: 'Mais sábio é o preguiçoso a seus olhos do que sete homens que sabem responder bem.' },
      { v: 17, en: 'Like one who grabs a dog’s ears is one who passes by and meddles in a quarrel not his own.', pt: 'O que, passando, se mete em questão alheia é como aquele que toma um cão pelas orelhas.' },
      { v: 18, en: 'Like a madman who shoots torches, arrows, and death,', pt: 'Como o louco que atira tições, flechas, e morte,' },
      { v: 19, en: 'is the man who deceives his neighbor and says, “Am I not joking?”', pt: 'assim é o homem que engana o seu próximo, e diz: Fiz isso por brincadeira.' },
      { v: 20, en: 'For lack of wood a fire goes out. Without gossip, a quarrel dies down.', pt: 'Faltando lenha, apaga-se o fogo; e não havendo difamador, cessa a contenda.' },
      { v: 21, en: 'As coals are to hot embers, and wood to fire, so is a contentious man to kindling strife.', pt: 'Como o carvão para as brasas, e a lenha para o fogo, assim é o homem contencioso para acender rixas.' },
      { v: 22, en: 'The words of a whisperer are as dainty morsels, they go down into the innermost parts.', pt: 'As palavras do difamador são como bocados deliciosos, que descem ao íntimo do ventre.' },
      { v: 23, en: 'Like silver dross on an earthen vessel are the lips of a fervent one with an evil heart.', pt: 'Como o vaso de barro coberto de escória de prata, assim são os lábios ardentes e o coração maligno.' },
      { v: 24, en: 'A malicious man disguises himself with his lips, but he harbors evil in his heart.', pt: 'Aquele que odeia dissimula com os seus lábios; mas no seu interior entesoura o engano.' },
      { v: 25, en: 'When his speech is charming, don’t believe him; for there are seven abominations in his heart.', pt: 'Quando te suplicar com voz suave, não o creias; porque sete abominações há no teu coração.' },
      { v: 26, en: 'His malice may be concealed by deception, but his wickedness will be exposed in the assembly.', pt: 'Ainda que o seu ódio se encubra com dissimulação, na congregação será revelada a sua malícia.' },
      { v: 27, en: 'Whoever digs a pit shall fall into it. Whoever rolls a stone, it will come back on him.', pt: 'O que faz uma cova cairá nela; e a pedra voltará sobre aquele que a revolve.' },
      { v: 28, en: 'A lying tongue hates those it hurts; and a flattering mouth works ruin.', pt: 'A língua falsa odeia aqueles a quem ela tenha ferido; e a boca lisonjeira opera a ruína.' },
    ],
    27: [
      { v: 1, en: 'Don’t boast about tomorrow; for you don’t know what a day may bring.', pt: 'Não te glories do dia de amanhã; porque não sabes o que produzirá o dia.' },
      { v: 2, en: 'Let another man praise you, and not your own mouth; a stranger, and not your own lips.', pt: 'Seja outro o que te louve, e não a tua boca; o estranho, e não os teus lábios.' },
      { v: 3, en: 'A stone is heavy, and sand is a burden; but a fool’s provocation is heavier than both.', pt: 'Pesada é a pedra, e a areia também; mas a ira do insensato é mais pesada do que elas ambas.' },
      { v: 4, en: 'Wrath is cruel, and anger is overwhelming; but who is able to stand before jealousy?', pt: 'Cruel é o furor, e impetuosa é a ira; mas quem pode resistir à inveja?' },
      { v: 5, en: 'Better is open rebuke than hidden love.', pt: 'Melhor é a repreensão aberta do que o amor encoberto.' },
      { v: 6, en: 'Faithful are the wounds of a friend; although the kisses of an enemy are profuse.', pt: 'Fiéis são as feridas dum amigo; mas os beijos dum inimigo são enganosos.' },
      { v: 7, en: 'A full soul loathes a honeycomb; but to a hungry soul, every bitter thing is sweet.', pt: 'O que está farto despreza o favo de mel; mas para o faminto todo amargo é doce.' },
      { v: 8, en: 'As a bird that wanders from her nest, so is a man who wanders from his home.', pt: 'Qual a ave que vagueia longe do seu ninho, tal é o homem que anda vagueando longe do seu lugar.' },
      { v: 9, en: 'Perfume and incense bring joy to the heart; so does earnest counsel from a man’s friend.', pt: 'O óleo e o perfume alegram o coração; assim é o doce conselho do homem para o seu amigo.' },
      { v: 10, en: 'Don’t forsake your friend and your father’s friend. Don’t go to your brother’s house in the day of your disaster: better is a neighbor who is near than a distant brother.', pt: 'Não abandones o teu amigo, nem o amigo de teu pai; nem entres na casa de teu irmão no dia de tua adversidade. Mais vale um vizinho que está perto do que um irmão que está longe.' },
      { v: 11, en: 'Be wise, my son, and bring joy to my heart, then I can answer my tormentor.', pt: 'Sê sábio, filho meu, e alegra o meu coração, para que eu tenha o que responder àquele que me vituperar.' },
      { v: 12, en: 'A prudent man sees danger and takes refuge; but the simple pass on, and suffer for it.', pt: 'O prudente vê o mal e se esconde; mas os insensatos passam adiante e sofrem a pena.' },
      { v: 13, en: 'Take his garment when he puts up collateral for a stranger. Hold it for a wayward woman!', pt: 'Tira a roupa àquele que fica por fiador do estranho, e toma penhor daquele que se obriga por uma estrangeira.' },
      { v: 14, en: 'He who blesses his neighbor with a loud voice early in the morning, it will be taken as a curse by him.', pt: 'O que bendiz ao seu amigo em alta voz, levantando-se de madrugada, isso lhe será contado como maldição.' },
      { v: 15, en: 'A continual dropping on a rainy day and a contentious wife are alike:', pt: 'A goteira contínua num dia chuvoso e a mulher rixosa são semelhantes;' },
      { v: 16, en: 'restraining her is like restraining the wind, or like grasping oil in his right hand.', pt: 'retê-la é reter o vento, ou segurar o óleo com a destra.' },
      { v: 17, en: 'Iron sharpens iron; so a man sharpens his friend’s countenance.', pt: 'Afia-se o ferro com o ferro; assim o homem afia o rosto do seu amigo.' },
      { v: 18, en: 'Whoever tends the fig tree shall eat its fruit. He who looks after his master shall be honored.', pt: 'O que cuida da figueira comerá do fruto dela; e o que vela pelo seu senhor será honrado.' },
      { v: 19, en: 'Like water reflects a face, so a man’s heart reflects the man.', pt: 'Como na água o rosto corresponde ao rosto, assim o coração do homem ao homem.' },
      { v: 20, en: 'Sheol and Abaddon are never satisfied; and a man’s eyes are never satisfied.', pt: 'O Seol e o Abadom nunca se fartam, e os olhos do homem nunca se satisfazem.' },
      { v: 21, en: 'The crucible is for silver, and the furnace for gold; but man is refined by his praise.', pt: 'O crisol é para a prata, e o forno para o ouro, e o homem é provado pelos louvores que recebe.' },
      { v: 22, en: 'Though you grind a fool in a mortar with a pestle along with grain, yet his foolishness will not be removed from him.', pt: 'Ainda que pisasses o insensato no gral entre grãos pilados, contudo não se apartaria dele a sua estultícia.' },
      { v: 23, en: 'Know well the state of your flocks, and pay attention to your herds:', pt: 'Procura conhecer o estado das tuas ovelhas; cuida bem dos teus rebanhos;' },
      { v: 24, en: 'for riches are not forever, nor does the crown endure to all generations.', pt: 'porque as riquezas não duram para sempre; e duraria a coroa de geração em geração?' },
      { v: 25, en: 'The hay is removed, and the new growth appears, the grasses of the hills are gathered in.', pt: 'Quando o feno é removido, e aparece a erva verde, e recolhem-se as ervas dos montes,' },
      { v: 26, en: 'The lambs are for your clothing, and the goats are the price of a field.', pt: 'os cordeiros te proverão de vestes, e os bodes, do preço do campo.' },
      { v: 27, en: 'There will be plenty of goats’ milk for your food, for your family’s food, and for the nourishment of your servant girls.', pt: 'E haverá bastante leite de cabras para o teu sustento, para o sustento da tua casa e das tuas criadas.' },
    ],
    28: [
      { v: 1, en: 'The wicked flee when no one pursues; but the righteous are as bold as a lion.', pt: 'Fogem os ímpios, sem que ninguém os persiga; mas os justos são ousados como o leão.' },
      { v: 2, en: 'In rebellion, a land has many rulers, but order is maintained by a man of understanding and knowledge.', pt: 'Por causa da transgressão duma terra são muitos os seus príncipes; mas por virtude de homens prudentes e entendidos, ela subsistirá por longo tempo.' },
      { v: 3, en: 'A needy man who oppresses the poor is like a driving rain which leaves no crops.', pt: 'O homem pobre que oprime os pobres, é como chuva impetuosa, que não deixa trigo nenhum.' },
      { v: 4, en: 'Those who forsake the law praise the wicked; but those who keep the law contend with them.', pt: 'Os que abandonam a lei louvam os ímpios; mas os que guardam a lei pelejam contra eles.' },
      { v: 5, en: 'Evil men don’t understand justice; but those who seek Yahweh understand it fully.', pt: 'Os homens maus não entendem a justiça; mas os que buscam ao Senhor a entendem plenamente.' },
      { v: 6, en: 'Better is the poor who walks in his integrity, than he who is perverse in his ways, and he is rich.', pt: 'Melhor é o pobre que anda na sua integridade, do que o rico perverso nos seus caminhos.' },
      { v: 7, en: 'Whoever keeps the law is a wise son; but he who is a companion of gluttons shames his father.', pt: 'O que guarda a lei é filho sábio; mas o companheiro dos comilões envergonha a seu pai.' },
      { v: 8, en: 'He who increases his wealth by excessive interest gathers it for one who has pity on the poor.', pt: 'O que aumenta a sua riqueza com juros e usura, ajunta-a para o que se compadece do pobre.' },
      { v: 9, en: 'He who turns away his ear from hearing the law, even his prayer is an abomination.', pt: 'O que desvia os seus ouvidos de ouvir a lei, até a sua oração é abominável.' },
      { v: 10, en: 'Whoever causes the upright to go astray in an evil way, he will fall into his own trap; but the blameless will inherit good.', pt: 'O que faz com que os retos se desviem para um mau caminho, ele mesmo cairá na cova que abriu; mas os inocentes herdarão o bem.' },
      { v: 11, en: 'The rich man is wise in his own eyes; but the poor who has understanding sees through him.', pt: 'O homem rico é sábio aos seus próprios olhos; mas o pobre que tem entendimento o esquadrinha.' },
      { v: 12, en: 'When the righteous triumph, there is great glory; but when the wicked rise, men hide themselves.', pt: 'Quando os justos triunfam há grande, glória; mas quando os ímpios sobem, escondem-se os homens.' },
      { v: 13, en: 'He who conceals his sins doesn’t prosper, but whoever confesses and renounces them finds mercy.', pt: 'O que encobre as suas transgressões nunca prosperará; mas o que as confessa e deixa, alcançará misericórdia.' },
      { v: 14, en: 'Blessed is the man who always fears; but one who hardens his heart falls into trouble.', pt: 'Feliz é o homem que teme ao Senhor continuamente; mas o que endurece o seu coração virá a cair no mal.' },
      { v: 15, en: 'As a roaring lion or a charging bear, so is a wicked ruler over helpless people.', pt: 'Como leão bramidor, e urso faminto, assim é o ímpio que domina sobre um povo pobre.' },
      { v: 16, en: 'A tyrannical ruler lacks judgment. One who hates ill-gotten gain will have long days.', pt: 'O príncipe falto de entendimento é também opressor cruel; mas o que aborrece a avareza prolongará os seus dias.' },
      { v: 17, en: 'A man who is tormented by life blood will be a fugitive until death; no one will support him.', pt: 'O homem culpado do sangue de qualquer pessoa será fugitivo até a morte; ninguém o ajude.' },
      { v: 18, en: 'Whoever walks blamelessly is kept safe; but one with perverse ways will fall suddenly.', pt: 'O que anda retamente salvar-se-á; mas o perverso em seus caminhos cairá de repente.' },
      { v: 19, en: 'One who works his land will have an abundance of food; but one who chases fantasies will have his fill of poverty.', pt: 'O que lavra a sua terra se fartará de pão; mas o que segue os ociosos se encherá de pobreza.' },
      { v: 20, en: 'A faithful man is rich with blessings; but one who is eager to be rich will not go unpunished.', pt: 'O homem fiel gozará de abundantes bênçãos; mas o que se apressa a enriquecer não ficará impune.' },
      { v: 21, en: 'To show partiality is not good; yet a man will do wrong for a piece of bread.', pt: 'Fazer acepção de pessoas não é bom; mas até por um bocado de pão prevaricará o homem.' },
      { v: 22, en: 'A stingy man hurries after riches, and doesn’t know that poverty waits for him.', pt: 'Aquele que é cobiçoso corre atrás das riquezas; e não sabe que há de vir sobre ele a penúria.' },
      { v: 23, en: 'One who rebukes a man will afterward find more favor than one who flatters with the tongue.', pt: 'O que repreende a um homem achará depois mais favor do que aquele que lisonjeia com a língua.' },
      { v: 24, en: 'Whoever robs his father or his mother, and says, “It’s not wrong.” He is a partner with a destroyer.', pt: 'O que rouba a seu pai, ou a sua mãe, e diz: Isso não é transgressão; esse é companheiro do destruidor.' },
      { v: 25, en: 'One who is greedy stirs up strife; but one who trusts in Yahweh will prosper.', pt: 'O cobiçoso levanta contendas; mas o que confia no senhor prosperará.' },
      { v: 26, en: 'One who trusts in himself is a fool; but one who walks in wisdom is kept safe.', pt: 'O que confia no seu próprio coração é insensato; mas o que anda sabiamente será livre.' },
      { v: 27, en: 'One who gives to the poor has no lack; but one who closes his eyes will have many curses.', pt: 'O que dá ao pobre não terá falta; mas o que esconde os seus olhos terá muitas maldições.' },
      { v: 28, en: 'When the wicked rise, men hide themselves; but when they perish, the righteous thrive.', pt: 'Quando os ímpios sobem, escondem-se os homens; mas quando eles perecem, multiplicam-se os justos.' },
    ],
    29: [
      { v: 1, en: 'He who is often rebuked and stiffens his neck will be destroyed suddenly, with no remedy.', pt: 'Aquele que, sendo muitas vezes repreendido, endurece a cerviz, será quebrantado de repente sem que haja cura.' },
      { v: 2, en: 'When the righteous thrive, the people rejoice; but when the wicked rule, the people groan.', pt: 'Quando os justos governam, alegra-se o povo; mas quando o ímpio domina, o povo geme.' },
      { v: 3, en: 'Whoever loves wisdom brings joy to his father; but a companion of prostitutes squanders his wealth.', pt: 'O que ama a sabedoria alegra a seu pai; mas o companheiro de prostitutas desperdiça a sua riqueza.' },
      { v: 4, en: 'The king by justice makes the land stable, but he who takes bribes tears it down.', pt: 'O rei pela justiça estabelece a terra; mas o que exige presentes a transtorna.' },
      { v: 5, en: 'A man who flatters his neighbor spreads a net for his feet.', pt: 'O homem que lisonjeia a seu próximo arma-lhe uma rede aos passos.' },
      { v: 6, en: 'An evil man is snared by his sin, but the righteous can sing and be glad.', pt: 'Na transgressão do homem mau há laço; mas o justo canta e se regozija.' },
      { v: 7, en: 'The righteous care about justice for the poor. The wicked aren’t concerned about knowledge.', pt: 'O justo toma conhecimento da causa dos pobres; mas o ímpio não tem entendimento para a conhecer.' },
      { v: 8, en: 'Mockers stir up a city, but wise men turn away anger.', pt: 'Os escarnecedores abrasam a cidade; mas os sábios desviam a ira.' },
      { v: 9, en: 'If a wise man goes to court with a foolish man, the fool rages or scoffs, and there is no peace.', pt: 'O sábio que pleiteia com o insensato, quer este se agaste quer se ria, não terá descanso.' },
      { v: 10, en: 'The bloodthirsty hate a man of integrity; and they seek the life of the upright.', pt: 'Os homens sanguinários odeiam o íntegro; mas os retos procuram o seu bem.' },
      { v: 11, en: 'A fool vents all of his anger, but a wise man brings himself under control.', pt: 'O tolo derrama toda a sua ira; mas o sábio a reprime e aplaca.' },
      { v: 12, en: 'If a ruler listens to lies, all of his officials are wicked.', pt: 'O governador que dá atenção às palavras mentirosas achará que todos os seus servos são ímpios.' },
      { v: 13, en: 'The poor man and the oppressor have this in common: Yahweh gives sight to the eyes of both.', pt: 'O pobre e o opressor se encontram; o Senhor alumia os olhos de ambos.' },
      { v: 14, en: 'The king who fairly judges the poor, his throne shall be established forever.', pt: 'Se o rei julgar os pobres com eqüidade, o seu trono será estabelecido para sempre.' },
      { v: 15, en: 'The rod of correction gives wisdom, but a child left to himself causes shame to his mother.', pt: 'A vara e a repreensão dão sabedoria; mas a criança entregue a si mesma envergonha a sua mãe.' },
      { v: 16, en: 'When the wicked increase, sin increases; but the righteous will see their downfall.', pt: 'Quando os ímpios se multiplicam, multiplicam-se as transgressões; mas os justos verão a queda deles.' },
      { v: 17, en: 'Correct your son, and he will give you peace; yes, he will bring delight to your soul.', pt: 'Corrige a teu filho, e ele te dará descanso; sim, deleitará o teu coração.' },
      { v: 18, en: 'Where there is no revelation, the people cast off restraint; but one who keeps the law is blessed.', pt: 'Onde não há profecia, o povo se corrompe; mas o que guarda a lei esse é bem-aventurado.' },
      { v: 19, en: 'A servant can’t be corrected by words. Though he understands, yet he will not respond.', pt: 'O servo não se emendará com palavras; porque, ainda que entenda, não atenderá.' },
      { v: 20, en: 'Do you see a man who is hasty in his words? There is more hope for a fool than for him.', pt: 'Vês um homem precipitado nas suas palavras? Maior esperança há para o tolo do que para ele.' },
      { v: 21, en: 'He who pampers his servant from youth will have him become a son in the end.', pt: 'Aquele que cria delicadamente o seu servo desde a meninice, no fim tê-lo-á por herdeiro.' },
      { v: 22, en: 'An angry man stirs up strife, and a wrathful man abounds in sin.', pt: 'O homem iracundo levanta contendas, e o furioso multiplica as transgressões.' },
      { v: 23, en: 'A man’s pride brings him low, but one of lowly spirit gains honor.', pt: 'A soberba do homem o abaterá; mas o humilde de espírito obterá honra.' },
      { v: 24, en: 'Whoever is an accomplice of a thief is an enemy of his own soul. He takes an oath, but dares not testify.', pt: 'O que é sócio do ladrão odeia a sua própria alma; sendo ajuramentado, nada denuncia.' },
      { v: 25, en: 'The fear of man proves to be a snare, but whoever puts his trust in Yahweh is kept safe.', pt: 'O receio do homem lhe arma laços; mas o que confia no Senhor está seguro.' },
      { v: 26, en: 'Many seek the ruler’s favor, but a man’s justice comes from Yahweh.', pt: 'Muitos buscam o favor do príncipe; mas é do Senhor que o homem recebe a justiça.' },
      { v: 27, en: 'A dishonest man detests the righteous, and the upright in their ways detest the wicked.', pt: 'O ímpio é abominação para os justos; e o que é reto no seu caminho é abominação para o ímpio.' },
    ],
    30: [
      { v: 1, en: 'The words of Agur the son of Jakeh; the revelation: the man says to Ithiel, to Ithiel and Ucal:', pt: 'Palavras de Agur, filho de Jaqué de Massá. Diz o homem a Itiel, e a Ucal:' },
      { v: 2, en: '“Surely I am the most ignorant man, and don’t have a man’s understanding.', pt: 'Na verdade que eu sou mais estúpido do que ninguém; não tenho o entendimento do homem;' },
      { v: 3, en: 'I have not learned wisdom, neither do I have the knowledge of the Holy One.', pt: 'não aprendi a sabedoria, nem tenho o conhecimento do Santo.' },
      { v: 4, en: 'Who has ascended up into heaven, and descended? Who has gathered the wind in his fists? Who has bound the waters in his garment? Who has established all the ends of the earth? What is his name, and what is his son’s name, if you know?', pt: 'Quem subiu ao céu e desceu? quem encerrou os ventos nos seus punhos? mas amarrou as águas no seu manto? quem estabeleceu todas as extremidades da terra? qual é o seu nome, e qual é o nome de seu filho? Certamente o sabes!' },
      { v: 5, en: '“Every word of God is flawless. He is a shield to those who take refuge in him.', pt: 'Toda palavra de Deus é pura; ele é um escudo para os que nele confiam.' },
      { v: 6, en: 'Don’t you add to his words, lest he reprove you, and you be found a liar.', pt: 'Nada acrescentes às suas palavras, para que ele não te repreenda e tu sejas achado mentiroso.' },
      { v: 7, en: '“Two things I have asked of you; don’t deny me before I die:', pt: 'Duas coisas te peço; não mas negues, antes que morra:' },
      { v: 8, en: 'Remove far from me falsehood and lies. Give me neither poverty nor riches. Feed me with the food that is needful for me;', pt: 'Alonga de mim a falsidade e a mentira; não me dês nem a pobreza nem a riqueza: dá-me só o pão que me é necessário;' },
      { v: 9, en: 'lest I be full, deny you, and say, ‘Who is Yahweh?’ or lest I be poor, and steal, and so dishonor the name of my God.', pt: 'para que eu de farto não te negue, e diga: Quem é o Senhor? ou, empobrecendo, não venha a furtar, e profane o nome de Deus.' },
      { v: 10, en: '“Don’t slander a servant to his master, lest he curse you, and you be held guilty.', pt: 'Não calunies o servo diante de seu senhor, para que ele não te amaldiçoe e fiques tu culpado.' },
      { v: 11, en: 'There is a generation that curses their father, and doesn’t bless their mother.', pt: 'Há gente que amaldiçoa a seu pai, e que não bendiz a sua mãe.' },
      { v: 12, en: 'There is a generation that is pure in their own eyes, yet are not washed from their filthiness.', pt: 'Há gente que é pura aos seus olhos, e contudo nunca foi lavada da sua imundícia.' },
      { v: 13, en: 'There is a generation, oh how lofty are their eyes! Their eyelids are lifted up.', pt: 'Há gente cujos olhos são altivos, e cujas pálpebras são levantadas para cima.' },
      { v: 14, en: 'There is a generation whose teeth are like swords, and their jaws like knives, to devour the poor from the earth, and the needy from among men.', pt: 'Há gente cujos dentes são como espadas; e cujos queixais sao como facas, para devorarem da terra os aflitos, e os necessitados dentre os homens.' },
      { v: 15, en: '“The leach has two daughters: ‘Give, give.’ “There are three things that are never satisfied; four that don’t say, ‘Enough:’', pt: 'A sanguessuga tem duas filhas, a saber: Dá, Dá. Há três coisas que nunca se fartam; sim, quatro que nunca dizem: Basta;' },
      { v: 16, en: 'Sheol, the barren womb; the earth that is not satisfied with water; and the fire that doesn’t say, ‘Enough.’', pt: 'o Seol, a madre estéril, a terra que não se farta d\'água, e o fogo que nunca diz: Basta.' },
      { v: 17, en: '“The eye that mocks at his father, and scorns obedience to his mother: the ravens of the valley shall pick it out, the young eagles shall eat it.', pt: 'Os olhos que zombam do pai, ou desprezam a obediência à mãe, serão arrancados pelos corvos do vale e devorados pelos filhos da águia.' },
      { v: 18, en: '“There are three things which are too amazing for me, four which I don’t understand:', pt: 'Há três coisas que são maravilhosas demais para mim, sim, há quatro que não conheço:' },
      { v: 19, en: 'The way of an eagle in the air; the way of a serpent on a rock; the way of a ship in the middle of the sea; and the way of a man with a maiden.', pt: 'o caminho da águia no ar, o caminho da cobra na penha, o caminho do navio no meio do mar, e o caminho do homem com uma virgem.' },
      { v: 20, en: '“So is the way of an adulterous woman: she eats and wipes her mouth, and says, ‘I have done nothing wrong.’', pt: 'Tal é o caminho da mulher adúltera: ela come, e limpa a sua boca, e diz: não pratiquei iniqüidade.' },
      { v: 21, en: '“For three things the earth trembles, and under four, it can’t bear up:', pt: 'Por três coisas estremece a terra, sim, há quatro que não pode suportar:' },
      { v: 22, en: 'For a servant when he is king; a fool when he is filled with food;', pt: 'o escravo quando reina; o tolo quando se farta de comer;' },
      { v: 23, en: 'for an unloved woman when she is married; and a servant who is heir to her mistress.', pt: 'a mulher desdenhada quando se casa; e a serva quando fica herdeira da sua senhora.' },
      { v: 24, en: '“There are four things which are little on the earth, but they are exceedingly wise:', pt: 'Quatro coisas há na terra que são pequenas, entretanto são extremamente sábias;' },
      { v: 25, en: 'the ants are not a strong people, yet they provide their food in the summer.', pt: 'as formigas são um povo sem força, todavia no verão preparam a sua comida;' },
      { v: 26, en: 'The conies are but a feeble folk, yet make they their houses in the rocks.', pt: 'os querogrilos são um povo débil, contudo fazem a sua casa nas rochas;' },
      { v: 27, en: 'The locusts have no king, yet they advance in ranks.', pt: 'os gafanhotos não têm rei, contudo marcham todos enfileirados;' },
      { v: 28, en: 'You can catch a lizard with your hands, yet it is in kings’ palaces.', pt: 'a lagartixa apanha-se com as mãos, contudo anda nos palácios dos reis.' },
      { v: 29, en: '“There are three things which are stately in their march, four which are stately in going:', pt: 'Há três que andam com elegância, sim, quatro que se movem airosamente:' },
      { v: 30, en: 'The lion, which is mightiest among animals, and doesn’t turn away for any;', pt: 'o leão, que é o mais forte entre os animais, e que não se desvia diante de ninguém;' },
      { v: 31, en: 'the greyhound, the male goat also; and the king against whom there is no rising up.', pt: 'o galo emproado, o bode, e o rei à frente do seu povo.' },
      { v: 32, en: '“If you have done foolishly in lifting up yourself, or if you have thought evil, put your hand over your mouth.', pt: 'Se procedeste loucamente em te elevares, ou se maquinaste o mal, põe a mão sobre a boca.' },
      { v: 33, en: 'For as the churning of milk produces butter, and the wringing of the nose produces blood; so the forcing of wrath produces strife.”', pt: 'Como o espremer do leite produz queijo verde, e o espremer do nariz produz sangue, assim o espremer da ira produz contenda.' },
    ],
    31: [
      { v: 1, en: 'The words of king Lemuel; the revelation which his mother taught him.', pt: 'As palavras do rei Lemuel, rei de Massá, que lhe ensinou sua mãe.' },
      { v: 2, en: '“Oh, my son! Oh, son of my womb! Oh, son of my vows!', pt: 'Que te direi, filho meu? e que te direi, ó filho do meu ventre? e que te direi, ó filho dos meus votos?' },
      { v: 3, en: 'Don’t give your strength to women, nor your ways to that which destroys kings.', pt: 'Não dês às mulheres a tua força, nem os teus caminhos às que destroem os reis.' },
      { v: 4, en: 'It is not for kings, Lemuel; it is not for kings to drink wine; nor for princes to say, ‘Where is strong drink?’', pt: 'Não é dos reis, ó Lemuel, não é dos reis beber vinho, nem dos príncipes desejar bebida forte;' },
      { v: 5, en: 'lest they drink, and forget the law, and pervert the justice due to anyone who is afflicted.', pt: 'para que não bebam, e se esqueçam da lei, e pervertam o direito de quem anda aflito.' },
      { v: 6, en: 'Give strong drink to him who is ready to perish; and wine to the bitter in soul:', pt: 'Dai bebida forte ao que está para perecer, e o vinho ao que está em amargura de espírito.' },
      { v: 7, en: 'Let him drink, and forget his poverty, and remember his misery no more.', pt: 'Bebam e se esqueçam da sua pobreza, e da sua miséria não se lembrem mais.' },
      { v: 8, en: 'Open your mouth for the mute, in the cause of all who are left desolate.', pt: 'Abre a tua boca a favor do mudo, a favor do direito de todos os desamparados.' },
      { v: 9, en: 'Open your mouth, judge righteously, and serve justice to the poor and needy.”', pt: 'Abre a tua boca; julga retamente, e faze justiça aos pobres e aos necessitados.' },
      { v: 10, en: 'Who can find a worthy woman? For her price is far above rubies.', pt: 'Álefe. Mulher virtuosa, quem a pode achar? Pois o seu valor muito excede ao de jóias preciosas.' },
      { v: 11, en: 'The heart of her husband trusts in her. He shall have no lack of gain.', pt: 'Bete. O coração do seu marido confia nela, e não lhe haverá falta de lucro.' },
      { v: 12, en: 'She does him good, and not harm, all the days of her life.', pt: 'Guímel. Ela lhe faz bem, e não mal, todos os dias da sua vida.' },
      { v: 13, en: 'She seeks wool and flax, and works eagerly with her hands.', pt: 'Dálete. Ela busca lã e linho, e trabalha de boa vontade com as mãos.' },
      { v: 14, en: 'She is like the merchant ships. She brings her bread from afar.', pt: 'Hê. É como os navios do negociante; de longe traz o seu pão.' },
      { v: 15, en: 'She rises also while it is yet night, gives food to her household, and portions for her servant girls.', pt: 'Vave. E quando ainda está escuro, ela se levanta, e dá mantimento à sua casa, e a tarefa às suas servas.' },
      { v: 16, en: 'She considers a field, and buys it. With the fruit of her hands, she plants a vineyard.', pt: 'Zaine. Considera um campo, e compra-o; planta uma vinha com o fruto de suas maos.' },
      { v: 17, en: 'She arms her waist with strength, and makes her arms strong.', pt: 'Hete. Cinge os seus lombos de força, e fortalece os seus braços.' },
      { v: 18, en: 'She perceives that her merchandise is profitable. Her lamp doesn’t go out by night.', pt: 'Tete. Prova e vê que é boa a sua mercadoria; e a sua lâmpada não se apaga de noite.' },
      { v: 19, en: 'She lays her hands to the distaff, and her hands hold the spindle.', pt: 'Iode. Estende as mãos ao fuso, e as suas mãos pegam na roca.' },
      { v: 20, en: 'She opens her arms to the poor; yes, she extends her hands to the needy.', pt: 'Cafe. Abre a mão para o pobre; sim, ao necessitado estende as suas mãos.' },
      { v: 21, en: 'She is not afraid of the snow for her household; for all her household are clothed with scarlet.', pt: 'Lâmede. Não tem medo da neve pela sua família; pois todos os da sua casa estão vestidos de escarlate.' },
      { v: 22, en: 'She makes for herself carpets of tapestry. Her clothing is fine linen and purple.', pt: 'Meme. Faz para si cobertas; de linho fino e de púrpura é o seu vestido.' },
      { v: 23, en: 'Her husband is respected in the gates, when he sits among the elders of the land.', pt: 'Nune. Conhece-se o seu marido nas portas, quando se assenta entre os anciãos da terra.' },
      { v: 24, en: 'She makes linen garments and sells them, and delivers sashes to the merchant.', pt: 'Sâmerue. Faz vestidos de linho, e vende-os, e entrega cintas aos mercadores.' },
      { v: 25, en: 'Strength and dignity are her clothing. She laughs at the time to come.', pt: 'Aine. A força e a dignidade são os seus vestidos; e ri-se do tempo vindouro.' },
      { v: 26, en: 'She opens her mouth with wisdom. Faithful instruction is on her tongue.', pt: 'Pê. Abre a sua boca com sabedoria, e o ensino da benevolência está na sua língua.' },
      { v: 27, en: 'She looks well to the ways of her household, and doesn’t eat the bread of idleness.', pt: 'Tsadê. Olha pelo governo de sua casa, e não come o pão da preguiça.' },
      { v: 28, en: 'Her children rise up and call her blessed. Her husband also praises her:', pt: 'Côfe. Levantam-se seus filhos, e lhe chamam bem-aventurada, como também seu marido, que a louva, dizendo:' },
      { v: 29, en: '“Many women do noble things, but you excel them all.”', pt: 'Reche. Muitas mulheres têm procedido virtuosamente, mas tu a todas sobrepujas.' },
      { v: 30, en: 'Charm is deceitful, and beauty is vain; but a woman who fears Yahweh, she shall be praised.', pt: 'Chine. Enganosa é a graça, e vã é a formosura; mas a mulher que teme ao Senhor, essa será louvada.' },
      { v: 31, en: 'Give her of the fruit of her hands! Let her works praise her in the gates!', pt: 'Tau. Dai-lhe do fruto das suas mãos, e louvem-na nas portas as suas obras.' },
    ],
  },
};

export default book;
